    #[test]
    fn phase1_subbriefs_and_snags_track_relations_and_blocking() {
        let s = store();
        let mk = |t: &str| {
            s.create(
                t,
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap()
        };
        let parent = mk("parent");
        let c1 = mk("child-1");
        let c2 = mk("child-2");
        let blocker = mk("blocker");

        // Sub-briefs: idempotent, ordered, no self-link, validated.
        s.link_subbrief(&parent, &c1).unwrap();
        s.link_subbrief(&parent, &c2).unwrap();
        s.link_subbrief(&parent, &c1).unwrap(); // idempotent no-op
        assert_eq!(
            s.list_subbriefs(&parent).unwrap(),
            vec![c1.clone(), c2.clone()]
        );
        assert!(s.list_subbriefs(&c1).unwrap().is_empty());
        assert!(matches!(
            s.link_subbrief(&parent, &parent),
            Err(CoordinatorError::Invalid(_))
        ));
        assert!(matches!(
            s.link_subbrief(&parent, "nope"),
            Err(CoordinatorError::NotFound(_))
        ));

        // Snags + blocking.
        assert!(!s.is_blocked(&parent).unwrap());
        s.add_snag(&parent, &blocker).unwrap();
        s.add_snag(&parent, &blocker).unwrap(); // idempotent
        assert_eq!(s.list_snags(&parent).unwrap(), vec![blocker.clone()]);
        assert!(s.is_blocked(&parent).unwrap());

        // Locked rule: a cancelled blocker stays UNRESOLVED.
        s.set_board_status(&blocker, "cancelled").unwrap();
        assert!(s.is_blocked(&parent).unwrap());

        // Only `done` resolves a Snag.
        let p2 = mk("parent-2");
        let b3 = mk("blocker-3");
        s.set_brief_field(&b3, "assignee", "agt_work").unwrap();
        s.add_snag(&p2, &b3).unwrap();
        assert!(s.is_blocked(&p2).unwrap());
        for st in ["todo", "in_progress"] {
            s.set_board_status(&b3, st).unwrap();
        }
        move_to_review(&s, &b3);
        s.set_board_status(&b3, "done").unwrap();
        assert!(!s.is_blocked(&p2).unwrap());
    }

    #[test]
    fn phase1_dossiers_attach_durable_artifacts() {
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();
        let d1 = s
            .add_dossier(&id, "plan", "The Plan", "step 1\nstep 2")
            .unwrap();
        let _d2 = s
            .add_dossier(&id, "design", "The Design", "boxes & arrows")
            .unwrap();

        let metas = s.list_dossiers(&id).unwrap();
        assert_eq!(metas.len(), 2);
        let kinds: Vec<&str> = metas.iter().map(|m| m.kind.as_str()).collect();
        assert!(kinds.contains(&"plan") && kinds.contains(&"design"));

        let full = s.get_dossier(&d1).unwrap().unwrap();
        assert_eq!(full.title, "The Plan");
        assert_eq!(full.body, "step 1\nstep 2");
        assert_eq!(full.task_id, id);
        assert_eq!(full.kind, "plan");

        // Validation.
        assert!(matches!(
            s.add_dossier(&id, "", "t", "b"),
            Err(CoordinatorError::Invalid(_))
        ));
        assert!(matches!(
            s.add_dossier(&id, "plan", "", "b"),
            Err(CoordinatorError::Invalid(_))
        ));
        assert!(matches!(
            s.add_dossier("nope", "plan", "t", "b"),
            Err(CoordinatorError::NotFound(_))
        ));
        assert!(s.get_dossier("missing").unwrap().is_none());
    }

    // §1.8: a first `author` of a kind creates revision 1 with no prior link;
    // a matching-expected revise appends rev 2 linking the previous; a stale
    // expected refuses and writes nothing; a fork from a stale/base doc records
    // `forked_from_doc_id` even though the latest moved.
    #[test]
    fn dossier_author_revise_lock_and_fork() {
        use brief::{DossierAuthorMode, DossierAuthorOutcome};
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();

        // 1) First author → create, revision 1, no previous/fork link.
        let r1 = s
            .author_dossier(
                &id,
                "plan",
                "Plan v1",
                "first body",
                "founder",
                DossierAuthorMode::Revise,
                None,
                None,
            )
            .unwrap();
        let v1 = match r1 {
            DossierAuthorOutcome::Authored(a) => {
                assert_eq!(a.mode, "create");
                assert_eq!(a.revision_number, 1);
                assert_eq!(a.revision_of_doc_id, None);
                assert_eq!(a.forked_from_doc_id, None);
                assert_eq!(a.author.as_deref(), Some("founder"));
                a.doc_id
            }
            DossierAuthorOutcome::Stale(_) => panic!("first author must not be stale"),
            DossierAuthorOutcome::Locked(_) => panic!("first author must not be locked"),
        };

        // 2) Revise with the matching expected latest → revision 2 linking v1.
        let r2 = s
            .author_dossier(
                &id,
                "plan",
                "Plan v2",
                "second body",
                "founder",
                DossierAuthorMode::Revise,
                Some(&v1),
                None,
            )
            .unwrap();
        let v2 = match r2 {
            DossierAuthorOutcome::Authored(a) => {
                assert_eq!(a.mode, "revise");
                assert_eq!(a.revision_number, 2);
                assert_eq!(a.revision_of_doc_id.as_deref(), Some(v1.as_str()));
                a.doc_id
            }
            DossierAuthorOutcome::Stale(_) => panic!("matching expected must not be stale"),
            DossierAuthorOutcome::Locked(_) => panic!("matching expected must not be locked"),
        };
        // latest is now v2.
        assert_eq!(s.latest_dossier(&id, "plan").unwrap().unwrap().doc_id, v2);

        // 3) Stale revise: assert v1 is latest (it's not — v2 is) → refused, no
        //    write, no event.
        let before = s.list_dossiers(&id).unwrap().len();
        let stale = s
            .author_dossier(
                &id,
                "plan",
                "Plan stale",
                "stale body",
                "founder",
                DossierAuthorMode::Revise,
                Some(&v1),
                None,
            )
            .unwrap();
        match stale {
            DossierAuthorOutcome::Stale(st) => {
                assert!(st.stale);
                assert_eq!(st.expected_latest_doc_id.as_deref(), Some(v1.as_str()));
                assert_eq!(st.current_latest_doc_id.as_deref(), Some(v2.as_str()));
            }
            DossierAuthorOutcome::Authored(_) => panic!("stale revise must not write"),
            DossierAuthorOutcome::Locked(_) => panic!("stale revise must not be locked"),
        }
        assert_eq!(
            s.list_dossiers(&id).unwrap().len(),
            before,
            "no row written"
        );
        // latest unchanged.
        assert_eq!(s.latest_dossier(&id, "plan").unwrap().unwrap().doc_id, v2);

        // 4) Fork from the STALE base v1 (latest is v2) → succeeds, records the
        //    fork link, latest still moves to the fork (newest row).
        let r4 = s
            .author_dossier(
                &id,
                "plan",
                "Plan forked from v1",
                "forked body",
                "lead",
                DossierAuthorMode::Fork,
                None,
                Some(&v1),
            )
            .unwrap();
        match r4 {
            DossierAuthorOutcome::Authored(a) => {
                assert_eq!(a.mode, "fork");
                assert_eq!(a.forked_from_doc_id.as_deref(), Some(v1.as_str()));
                assert_eq!(a.revision_of_doc_id, None);
                assert_eq!(a.revision_number, 3);
            }
            DossierAuthorOutcome::Stale(_) => panic!("fork must not be stale"),
            DossierAuthorOutcome::Locked(_) => panic!("fork must not be locked"),
        }

        // Chronicle events: one create, one revise, one fork; the stale attempt
        // wrote none.
        let conn = s.conn.lock().unwrap();
        let count = |et: &str| -> i64 {
            conn.query_row(
                "SELECT COUNT(*) FROM task_events WHERE task_id = ?1 AND event_type = ?2",
                params![id, et],
                |r| r.get(0),
            )
            .unwrap()
        };
        assert_eq!(count("brief.dossier_authored"), 1);
        assert_eq!(count("brief.dossier_revised"), 1);
        assert_eq!(count("brief.dossier_forked"), 1);
    }

    // §1.8: author validation — empty kind/title/body and an unsafe kind token
    // refuse; a missing Brief / cross-Brief or cross-kind fork base refuse.
    #[test]
    fn dossier_author_validation_and_fork_base_guards() {
        use brief::{DossierAuthorMode, DossierAuthorOutcome};
        let s = store();
        let mk = |t: &str| {
            s.create(
                t,
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap()
        };
        let a = mk("a");
        let b = mk("b");
        let bad = |r: Result<DossierAuthorOutcome, CoordinatorError>| {
            assert!(matches!(r, Err(CoordinatorError::Invalid(_))));
        };
        bad(s.author_dossier(
            &a,
            "",
            "t",
            "body",
            "u",
            DossierAuthorMode::Revise,
            None,
            None,
        ));
        bad(s.author_dossier(
            &a,
            "pl an",
            "t",
            "body",
            "u",
            DossierAuthorMode::Revise,
            None,
            None,
        ));
        bad(s.author_dossier(
            &a,
            "plan",
            "",
            "body",
            "u",
            DossierAuthorMode::Revise,
            None,
            None,
        ));
        bad(s.author_dossier(
            &a,
            "plan",
            "t",
            "",
            "u",
            DossierAuthorMode::Revise,
            None,
            None,
        ));
        bad(s.author_dossier(
            &a,
            "plan",
            "t",
            "body",
            "",
            DossierAuthorMode::Revise,
            None,
            None,
        ));
        // Missing Brief.
        assert!(matches!(
            s.author_dossier(
                "nope",
                "plan",
                "t",
                "body",
                "u",
                DossierAuthorMode::Revise,
                None,
                None
            ),
            Err(CoordinatorError::NotFound(_))
        ));
        // Fork with no base id.
        bad(s.author_dossier(
            &a,
            "plan",
            "t",
            "body",
            "u",
            DossierAuthorMode::Fork,
            None,
            None,
        ));

        // Seed a plan on `a`; forking it from Brief `b` must refuse (cross-Brief
        // base), and forking a different kind must refuse (cross-kind base).
        let pa = match s
            .author_dossier(
                &a,
                "plan",
                "P",
                "pbody",
                "u",
                DossierAuthorMode::Revise,
                None,
                None,
            )
            .unwrap()
        {
            DossierAuthorOutcome::Authored(x) => x.doc_id,
            _ => unreachable!(),
        };
        bad(s.author_dossier(
            &b,
            "plan",
            "t",
            "body",
            "u",
            DossierAuthorMode::Fork,
            None,
            Some(&pa),
        ));
        bad(s.author_dossier(
            &a,
            "design",
            "t",
            "body",
            "u",
            DossierAuthorMode::Fork,
            None,
            Some(&pa),
        ));
    }

    // §1.8: the new authoring metadata surfaces on the Dossier reads, and a
    // legacy `add_dossier` row still reads back with a derived revision_number
    // and null authoring metadata (back-compatible).
    #[test]
    fn dossier_reads_carry_revision_metadata() {
        use brief::{DossierAuthorMode, DossierAuthorOutcome};
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();
        // A legacy add (no authoring metadata) is revision 1 of `notes`.
        let legacy = s.add_dossier(&id, "notes", "Note", "n").unwrap();
        let lg = s.get_dossier(&legacy).unwrap().unwrap();
        assert_eq!(lg.revision_number, 1);
        assert_eq!(lg.author, None);
        assert_eq!(lg.revision_of_doc_id, None);
        assert_eq!(lg.forked_from_doc_id, None);

        // Two authored plan revisions.
        let v1 = match s
            .author_dossier(
                &id,
                "plan",
                "P1",
                "b1",
                "founder",
                DossierAuthorMode::Revise,
                None,
                None,
            )
            .unwrap()
        {
            DossierAuthorOutcome::Authored(a) => a.doc_id,
            _ => unreachable!(),
        };
        s.author_dossier(
            &id,
            "plan",
            "P2",
            "b2",
            "founder",
            DossierAuthorMode::Revise,
            Some(&v1),
            None,
        )
        .unwrap();
        let latest = s.latest_dossier(&id, "plan").unwrap().unwrap();
        assert_eq!(latest.title, "P2");
        assert_eq!(latest.revision_number, 2);
        assert_eq!(latest.author.as_deref(), Some("founder"));
        assert_eq!(latest.revision_of_doc_id.as_deref(), Some(v1.as_str()));

        // list_dossiers carries per-kind revision numbers (notes rev 1, plan
        // rev 1 + 2).
        let metas = s.list_dossiers(&id).unwrap();
        let plan_revs: Vec<i64> = metas
            .iter()
            .filter(|m| m.kind == "plan")
            .map(|m| m.revision_number)
            .collect();
        assert_eq!(plan_revs, vec![1, 2]);
        let notes_rev = metas
            .iter()
            .find(|m| m.kind == "notes")
            .map(|m| m.revision_number);
        assert_eq!(notes_rev, Some(1));
    }

    // Prime governed Dossier authoring (company-model §12.5F): the helper that
    // the orchestration path uses writes a FIRST revision stamped as the
    // synthetic autonomous-Prime authority, is rerun-idempotent, never clobbers
    // a human/legacy doc, and refuses a lock held by someone else.
    #[test]
    fn author_prime_dossier_creates_prime_owned_then_idempotent() {
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();
        let prime = agent::prime_driver::AUTONOMOUS_PRIME_AUTHORITY;

        // First write → a Prime-owned `create` revision through author_dossier.
        match s
            .author_prime_dossier(&id, "orchestration", "Orchestration plan", "body v1")
            .unwrap()
        {
            brief::PrimeDossierOutcome::Authored(a) => {
                assert_eq!(a.mode, "create");
                assert_eq!(a.revision_number, 1);
                assert_eq!(a.author.as_deref(), Some(prime));
            }
            other => panic!("expected Authored, got {}", other.label()),
        }
        // The latest revision is stamped as the autonomous-Prime author (NOT a
        // legacy author-less `add_dossier` row).
        let latest = s.latest_dossier(&id, "orchestration").unwrap().unwrap();
        assert_eq!(latest.author.as_deref(), Some(prime));

        // Rerun is idempotent: no duplicate revision is appended.
        match s
            .author_prime_dossier(&id, "orchestration", "Orchestration plan", "body v2")
            .unwrap()
        {
            brief::PrimeDossierOutcome::AlreadyPresent { kind, doc_id } => {
                assert_eq!(kind, "orchestration");
                assert_eq!(doc_id, latest.doc_id);
            }
            other => panic!("expected AlreadyPresent, got {}", other.label()),
        }
        // Exactly one revision of this kind exists, with the original body.
        let metas = s.list_dossiers(&id).unwrap();
        assert_eq!(
            metas.iter().filter(|m| m.kind == "orchestration").count(),
            1
        );
        assert_eq!(
            s.latest_dossier(&id, "orchestration")
                .unwrap()
                .unwrap()
                .body,
            "body v1"
        );
    }

    #[test]
    fn author_prime_dossier_preserves_human_and_legacy_docs() {
        use brief::DossierAuthorMode;
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();

        // A human authored the `orchestration` kind first.
        s.author_dossier(
            &id,
            "orchestration",
            "Hand-written plan",
            "human body",
            "founder",
            DossierAuthorMode::Revise,
            None,
            None,
        )
        .unwrap();
        // Prime must NOT clobber it — skipped, human-owned, nothing appended.
        match s
            .author_prime_dossier(&id, "orchestration", "Orchestration plan", "prime body")
            .unwrap()
        {
            brief::PrimeDossierOutcome::SkippedHumanOwned { kind, author } => {
                assert_eq!(kind, "orchestration");
                assert_eq!(author.as_deref(), Some("founder"));
            }
            other => panic!("expected SkippedHumanOwned, got {}", other.label()),
        }
        let latest = s.latest_dossier(&id, "orchestration").unwrap().unwrap();
        assert_eq!(latest.author.as_deref(), Some("founder"));
        assert_eq!(latest.body, "human body");

        // A legacy author-less `add_dossier` row is likewise preserved.
        s.add_dossier(&id, "execution", "Legacy exec", "legacy body")
            .unwrap();
        match s
            .author_prime_dossier(&id, "execution", "Execution plan", "prime body")
            .unwrap()
        {
            brief::PrimeDossierOutcome::SkippedHumanOwned { author, .. } => {
                assert_eq!(author, None);
            }
            other => panic!("expected SkippedHumanOwned, got {}", other.label()),
        }
        assert_eq!(
            s.latest_dossier(&id, "execution").unwrap().unwrap().body,
            "legacy body"
        );
    }

    #[test]
    fn author_prime_dossier_refuses_lock_held_by_other() {
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();
        // A human locks the `orchestration` kind before Prime writes anything.
        match s
            .lock_dossier(&id, "orchestration", "founder", Some("editing"))
            .unwrap()
        {
            brief::DossierLockOutcome::Locked(_) => {}
            brief::DossierLockOutcome::Conflict(_) => panic!("first lock must not conflict"),
        }
        // Prime's governed write is refused — nothing written, no overwrite.
        match s
            .author_prime_dossier(&id, "orchestration", "Orchestration plan", "prime body")
            .unwrap()
        {
            brief::PrimeDossierOutcome::LockedByOther { kind, locked_by } => {
                assert_eq!(kind, "orchestration");
                assert_eq!(locked_by, "founder");
            }
            other => panic!("expected LockedByOther, got {}", other.label()),
        }
        assert!(s.latest_dossier(&id, "orchestration").unwrap().is_none());
    }

    #[test]
    fn phase1_brief_spine_fields_set_and_read() {
        let s = store();
        let id = s
            .create(
                "b",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();

        // Defaults.
        let f = s.brief_fields(&id).unwrap().unwrap();
        assert_eq!(f.board_status, "backlog");
        assert_eq!(f.priority, "normal");
        assert_eq!(f.assignee_agent_id, None);
        assert_eq!(f.mandate_id, None);
        assert_eq!(f.campaign_id, None);

        // Set each spine field.
        s.set_brief_field(&id, "assignee", "agt_eng_1").unwrap();
        s.set_brief_field(&id, "priority", "high").unwrap();
        s.set_brief_field(&id, "mandate", "mandate_x").unwrap();
        s.set_brief_field(&id, "campaign", "camp_y").unwrap();
        let f = s.brief_fields(&id).unwrap().unwrap();
        assert_eq!(f.assignee_agent_id.as_deref(), Some("agt_eng_1"));
        assert_eq!(f.priority, "high");
        assert_eq!(f.mandate_id.as_deref(), Some("mandate_x"));
        assert_eq!(f.campaign_id.as_deref(), Some("camp_y"));

        // Empty clears the soft links.
        s.set_brief_field(&id, "assignee", "").unwrap();
        assert_eq!(
            s.brief_fields(&id).unwrap().unwrap().assignee_agent_id,
            None
        );

        // Validation.
        assert!(matches!(
            s.set_brief_field(&id, "priority", "bogus"),
            Err(CoordinatorError::Invalid(_))
        ));
        assert!(matches!(
            s.set_brief_field(&id, "nope", "x"),
            Err(CoordinatorError::Invalid(_))
        ));
        assert!(matches!(
            s.set_brief_field("missing", "priority", "high"),
            Err(CoordinatorError::NotFound(_))
        ));

        // The one non-empty assignment was chronicled (clears aren't).
        let conn = s.conn.lock().unwrap();
        let n: i64 = conn
            .query_row(
                "SELECT COUNT(*) FROM task_events
                 WHERE task_id=?1 AND event_type='brief.assigned'",
                params![id],
                |r| r.get(0),
            )
            .unwrap();
        assert_eq!(n, 1);
    }

    #[test]
    fn phase2_brief_board_lists_by_column() {
        let s = store();
        let mk = |t: &str| {
            s.create(
                t,
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap()
        };
        let a = mk("a");
        let b = mk("b");
        let c = mk("c");
        // a, b stay in backlog; drive c to in_progress.
        s.set_board_status(&c, "todo").unwrap();
        move_to_progress(&s, &c);

        // All columns.
        assert_eq!(s.list_briefs_by_board(None, 50).unwrap().len(), 3);

        // One column.
        let backlog = s.list_briefs_by_board(Some("backlog"), 50).unwrap();
        assert_eq!(backlog.len(), 2);
        let ids: Vec<&str> = backlog.iter().map(|c| c.task_id.as_str()).collect();
        assert!(ids.contains(&a.as_str()) && ids.contains(&b.as_str()));

        let inprog = s.list_briefs_by_board(Some("in_progress"), 50).unwrap();
        assert_eq!(inprog.len(), 1);
        assert_eq!(inprog[0].task_id, c);
        assert_eq!(inprog[0].board_status, "in_progress");

        // Unknown column rejected.
        assert!(matches!(
            s.list_briefs_by_board(Some("bogus"), 50),
            Err(CoordinatorError::Invalid(_))
        ));

        // Cards carry the Brief's spine fields.
        s.set_brief_field(&c, "priority", "high").unwrap();
        s.set_brief_field(&c, "assignee", "agt_x").unwrap();
        let inprog = s.list_briefs_by_board(Some("in_progress"), 50).unwrap();
        assert_eq!(inprog[0].priority, "high");
        assert_eq!(inprog[0].assignee_agent_id.as_deref(), Some("agt_x"));
    }

