    #[test]
    fn tenant_scoped_reads_isolate_briefs_across_guilds() {
        // GROUP 6 / tenant isolation: a Brief created under Guild "acme"
        // must not surface through the board / inbox / detail / search
        // reads scoped to Guild "globex", and vice-versa.
        let s = store();
        let a = s
            .create_brief(
                "acme",
                "Quarterly board item",
                "subj",
                None,
                Some("m_a"),
                None,
                None,
            )
            .unwrap();
        let b = s
            .create_brief(
                "globex",
                "Quarterly board item",
                "subj",
                None,
                Some("m_b"),
                None,
                None,
            )
            .unwrap();
        // A legacy Task with NULL tenant_id resolves to the `default` Guild.
        let legacy = s
            .create(
                "legacy",
                "f",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();
        s.set_board_status(&legacy, "todo").unwrap();

        // Board column (todo): each Guild sees only its own Brief.
        let acme_todo = s
            .list_briefs_by_board_for_tenant(Some("todo"), "acme", 50)
            .unwrap();
        assert!(acme_todo.iter().any(|c| c.task_id == a));
        assert!(!acme_todo.iter().any(|c| c.task_id == b));
        assert!(!acme_todo.iter().any(|c| c.task_id == legacy));
        let globex_todo = s
            .list_briefs_by_board_for_tenant(Some("todo"), "globex", 50)
            .unwrap();
        assert!(globex_todo.iter().any(|c| c.task_id == b));
        assert!(!globex_todo.iter().any(|c| c.task_id == a));
        // The legacy NULL-tenant row is visible to the default Guild only.
        let default_todo = s
            .list_briefs_by_board_for_tenant(Some("todo"), "default", 50)
            .unwrap();
        assert!(default_todo.iter().any(|c| c.task_id == legacy));
        assert!(
            !default_todo
                .iter()
                .any(|c| c.task_id == a || c.task_id == b)
        );

        // Inbox surfaces: unassigned isolates per Guild.
        let acme_un = s.list_unassigned_briefs_for_tenant("acme", 50).unwrap();
        assert!(acme_un.iter().any(|c| c.task_id == a) && !acme_un.iter().any(|c| c.task_id == b));

        // Detail: a cross-Guild id reads as not-found (None).
        assert!(s.brief_detail_for_tenant(&a, "acme").unwrap().is_some());
        assert!(s.brief_detail_for_tenant(&a, "globex").unwrap().is_none());
        assert!(s.brief_detail_for_tenant(&b, "acme").unwrap().is_none());
        assert!(!s.task_in_tenant(&a, "globex").unwrap());

        // Search: the identical title is found once per Guild.
        assert_eq!(
            s.search_briefs_for_tenant("board item", "acme", 50)
                .unwrap()
                .len(),
            1
        );
        assert_eq!(
            s.search_briefs_for_tenant("board item", "globex", 50)
                .unwrap()
                .len(),
            1
        );

        // Board summary counts never cross Guilds.
        let acme_counts: std::collections::HashMap<String, i64> = s
            .board_summary_for_tenant("acme")
            .unwrap()
            .into_iter()
            .collect();
        assert_eq!(acme_counts.get("todo").copied().unwrap_or(0), 1);
    }

    /// Board cards carry their *unresolved* blockers so the board can show a
    /// "Blocked by X" chip without opening the detail (relix-dashboard-design
    /// §6). The list is honest and tenant-safe: a resolved (`done`) blocker
    /// drops off, a cross-Guild blocker is neither shown nor counted (no
    /// existence leak), and a non-blocked card stays empty.
    #[test]
    fn board_cards_carry_unresolved_blocker_refs_tenant_safe() {
        let s = store();
        // A waiter in acme, blocked by: one open same-Guild blocker (by ref),
        // one resolved same-Guild blocker, and one open cross-Guild blocker.
        let waiter = s
            .create_brief("acme", "waiter", "subj", None, None, None, None)
            .unwrap();
        let open = s
            .create_brief("acme", "open blocker", "subj", None, None, None, None)
            .unwrap();
        let resolved = s
            .create_brief("acme", "resolved blocker", "subj", None, None, None, None)
            .unwrap();
        let foreign = s
            .create_brief("globex", "globex blocker", "subj", None, None, None, None)
            .unwrap();
        // The open same-Guild blocker carries a human-ref → it should surface
        // by ref (e.g. REL-2), not by raw id.
        let open_ref = s.assign_brief_ref("acme", &open).unwrap();

        s.add_snag(&waiter, &open).unwrap();
        s.add_snag(&waiter, &resolved).unwrap();
        s.add_snag(&waiter, &foreign).unwrap();

        // Drive the `resolved` blocker to done so it no longer blocks.
        move_to_progress(&s, &resolved);
        move_to_review(&s, &resolved);
        s.set_board_status(&resolved, "done").unwrap();

        // A second acme card with no Snag stays uncluttered.
        let clear = s
            .create_brief("acme", "clear card", "subj", None, None, None, None)
            .unwrap();

        let acme_todo = s
            .list_briefs_by_board_for_tenant(Some("todo"), "acme", 50)
            .unwrap();
        let w = acme_todo
            .iter()
            .find(|c| c.task_id == waiter)
            .expect("waiter on the acme todo board");
        // Only the open, same-Guild blocker is shown — by its ref.
        assert_eq!(
            w.blocked_by,
            vec![open_ref],
            "only the open same-Guild blocker, by ref"
        );
        assert!(
            !w.blocked_by.contains(&resolved),
            "resolved blocker dropped"
        );
        assert!(
            !w.blocked_by.contains(&foreign),
            "cross-Guild blocker not leaked"
        );

        let c = acme_todo
            .iter()
            .find(|c| c.task_id == clear)
            .expect("clear card on the acme todo board");
        assert!(
            c.blocked_by.is_empty(),
            "a non-blocked card carries no blockers"
        );

        // The foreign blocker is real but isolated: globex sees no acme waiter.
        let globex_todo = s
            .list_briefs_by_board_for_tenant(Some("todo"), "globex", 50)
            .unwrap();
        assert!(!globex_todo.iter().any(|c| c.task_id == waiter));
    }

    #[test]
    fn phase2_desk_surfaces_blocked_and_stale_briefs() {
        let s = store();
        let mk = |t: &str| {
            s.create(
                t,
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap()
        };

        // Blocked: a live Brief with an unresolved Snag.
        let blocked = mk("blocked");
        let blocker = mk("blocker");
        s.set_board_status(&blocked, "todo").unwrap();
        s.set_brief_field(&blocker, "assignee", "agt_work").unwrap();
        s.add_snag(&blocked, &blocker).unwrap();
        let bl = s.list_blocked_briefs(50).unwrap();
        assert_eq!(bl.len(), 1);
        assert_eq!(bl[0].task_id, blocked);
        // Resolving the blocker drops it off.
        s.set_brief_field(&blocker, "assignee", "agt_work").unwrap();
        for st in ["todo", "in_progress"] {
            s.set_board_status(&blocker, st).unwrap();
        }
        move_to_review(&s, &blocker);
        s.set_board_status(&blocker, "done").unwrap();
        assert!(s.list_blocked_briefs(50).unwrap().is_empty());

        // Stale: an active Brief backdated past the idle window.
        let stale = mk("stale");
        move_to_progress(&s, &stale);
        {
            let conn = s.conn.lock().unwrap();
            conn.execute(
                "UPDATE tasks SET updated_at = 100 WHERE task_id = ?1",
                params![stale],
            )
            .unwrap();
        }
        let st = s.list_stale_briefs(0, 50).unwrap();
        assert!(st.iter().any(|c| c.task_id == stale));
        // A fresh active Brief is not stale.
        let fresh = mk("fresh");
        move_to_progress(&s, &fresh);
        assert!(
            !s.list_stale_briefs(0, 50)
                .unwrap()
                .iter()
                .any(|c| c.task_id == fresh)
        );
    }

    #[test]
    fn phase3_brief_claim_is_single_owner_with_lease() {
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();

        // Unclaimed to start.
        assert!(s.claim_holder(&id).unwrap().is_none());

        // A claims; B is locked out while A's lease is live.
        assert!(s.claim_brief(&id, "agt_a", 300).unwrap());
        assert_eq!(s.claim_holder(&id).unwrap().unwrap().0, "agt_a");
        assert!(!s.claim_brief(&id, "agt_b", 300).unwrap());

        // A is re-entrant; A heartbeats; B's heartbeat fails.
        assert!(s.claim_brief(&id, "agt_a", 300).unwrap());
        assert!(s.heartbeat_claim(&id, "agt_a", 300).unwrap());
        assert!(!s.heartbeat_claim(&id, "agt_b", 300).unwrap());

        // A releases; B can now claim.
        s.release_claim(&id, "agt_a").unwrap();
        assert!(s.claim_holder(&id).unwrap().is_none());
        assert!(s.claim_brief(&id, "agt_b", 300).unwrap());

        // An expired lease shows no holder and is reclaimable.
        {
            let conn = s.conn.lock().unwrap();
            conn.execute(
                "UPDATE tasks SET claim_expires_at = 100 WHERE task_id = ?1",
                params![id],
            )
            .unwrap();
        }
        assert!(s.claim_holder(&id).unwrap().is_none());
        assert!(s.claim_brief(&id, "agt_a", 300).unwrap());

        // Unknown Brief → NotFound.
        assert!(matches!(
            s.claim_brief("nope", "agt_a", 300),
            Err(CoordinatorError::NotFound(_))
        ));
    }

    #[test]
    fn agent_start_lock_is_per_operative_and_reused() {
        // execution-and-issue-design §2.6: the in-process start lock is keyed
        // per Operative. Same Operative → the SAME lock (so concurrent starts
        // for that Operative serialize); different Operatives → distinct locks
        // (so unrelated work proceeds in parallel).
        let s = store();
        let a1 = s.agent_start_lock("agt_a");
        let a2 = s.agent_start_lock(" agt_a "); // trimmed → same key
        let b = s.agent_start_lock("agt_b");
        assert!(
            Arc::ptr_eq(&a1, &a2),
            "the same Operative shares one start lock"
        );
        assert!(
            !Arc::ptr_eq(&a1, &b),
            "different Operatives get distinct start locks"
        );
    }

    #[test]
    fn concurrent_claims_by_distinct_operatives_one_wins_loser_conflicts() {
        // execution-and-issue-design §1.4/§7.1 (LOCKED two-pointer Claim):
        // two DIFFERENT Operatives race to Claim the same Brief. Exactly ONE
        // wins; the other gets a conflict (`Ok(false)`) — the refusal the HTTP
        // bridge surfaces as 409. The rule the loser must honor: NEVER retry a
        // 409 — a retry while the winner holds a live Claim only loses again.
        let s = Arc::new(store());
        let id = s
            .create(
                "contended",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();

        let barrier = Arc::new(std::sync::Barrier::new(2));
        let mut handles = Vec::new();
        for (agent, run) in [("agt_a", "run_a"), ("agt_b", "run_b")] {
            let s = s.clone();
            let id = id.clone();
            let barrier = barrier.clone();
            handles.push(std::thread::spawn(move || {
                barrier.wait();
                s.claim_brief_for_run(&id, agent, 300, Some(run)).unwrap()
            }));
        }
        let results: Vec<bool> = handles.into_iter().map(|h| h.join().unwrap()).collect();
        let winners = results.iter().filter(|won| **won).count();
        assert_eq!(
            winners, 1,
            "exactly one Operative wins the Claim; the other conflicts"
        );

        // Identify the loser and prove NEVER-retry-a-409: a retry by the loser
        // while the winner still holds a live Claim conflicts again.
        let holder = s.claim_holder(&id).unwrap().unwrap().0;
        let loser = if holder == "agt_a" { "agt_b" } else { "agt_a" };
        assert!(
            !s.claim_brief_for_run(&id, loser, 300, Some("retry"))
                .unwrap(),
            "retrying a 409 conflict loses again — clients must not retry"
        );
        // The winner's Claim is untouched by the loser's retry.
        assert_eq!(s.claim_holder(&id).unwrap().unwrap().0, holder);
    }

    #[test]
    fn phase3_claim_clears_when_brief_leaves_in_progress() {
        let s = store();
        let id = s
            .create(
                "brief",
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap();
        s.set_brief_field(&id, "assignee", "agt_a").unwrap();
        s.set_board_status(&id, "todo").unwrap();
        assert!(
            s.claim_brief_for_run(&id, "agt_a", 300, Some("shift_1"))
                .unwrap()
        );
        move_to_progress(&s, &id);
        assert_eq!(s.claim_holder(&id).unwrap().unwrap().0, "agt_a");

        move_to_review(&s, &id);
        assert!(s.claim_holder(&id).unwrap().is_none());
        let conn = s.conn.lock().unwrap();
        let snapshot: (Option<String>, Option<String>, Option<String>, Option<i64>) = conn
            .query_row(
                "SELECT checkout_run_id, execution_run_id, claim_agent_id, claim_locked_at
                 FROM tasks WHERE task_id = ?1",
                params![id],
                |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?)),
            )
            .unwrap();
        assert_eq!(snapshot, (None, None, None, None));
    }

    #[test]
    fn phase3_ready_briefs_are_assigned_unblocked_unclaimed_active() {
        let s = store();
        let mk = |t: &str| {
            s.create(
                t,
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap()
        };

        // Ready: assigned, todo, unblocked, unclaimed.
        let ready = mk("ready");
        s.set_brief_field(&ready, "assignee", "agt_a").unwrap();
        s.set_board_status(&ready, "todo").unwrap();

        // Not ready: no assignee.
        let unassigned = mk("unassigned");
        s.set_board_status(&unassigned, "todo").unwrap();

        // Not ready: blocked by an unresolved Snag.
        let blocked = mk("blocked");
        let blocker = mk("blocker");
        s.set_brief_field(&blocked, "assignee", "agt_b").unwrap();
        s.set_board_status(&blocked, "todo").unwrap();
        s.add_snag(&blocked, &blocker).unwrap();

        // Not ready: already claimed (live).
        let claimed = mk("claimed");
        s.set_brief_field(&claimed, "assignee", "agt_c").unwrap();
        s.set_board_status(&claimed, "todo").unwrap();
        assert!(s.claim_brief(&claimed, "agt_c", 300).unwrap());

        // Not ready: done.
        let done = mk("done");
        s.set_brief_field(&done, "assignee", "agt_d").unwrap();
        for st in ["todo", "in_progress"] {
            s.set_board_status(&done, st).unwrap();
        }
        move_to_review(&s, &done);
        s.set_board_status(&done, "done").unwrap();

        let ids: Vec<String> = s
            .list_ready_briefs(50)
            .unwrap()
            .into_iter()
            .map(|c| c.task_id)
            .collect();
        assert!(ids.contains(&ready));
        for not in [&unassigned, &blocked, &claimed, &done] {
            assert!(!ids.contains(not), "{not} should not be ready");
        }

        // Releasing the claim makes 'claimed' ready.
        s.release_claim(&claimed, "agt_c").unwrap();
        assert!(
            s.list_ready_briefs(50)
                .unwrap()
                .iter()
                .any(|c| c.task_id == claimed)
        );
        // Resolving the blocker makes 'blocked' ready.
        s.set_brief_field(&blocker, "assignee", "agt_work").unwrap();
        for st in ["todo", "in_progress"] {
            s.set_board_status(&blocker, st).unwrap();
        }
        move_to_review(&s, &blocker);
        s.set_board_status(&blocker, "done").unwrap();
        assert!(
            s.list_ready_briefs(50)
                .unwrap()
                .iter()
                .any(|c| c.task_id == blocked)
        );
    }

    #[test]
    fn phase3_children_completed_wake_surfaces_finished_parents() {
        let s = store();
        let mk = |t: &str| {
            s.create(
                t,
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap()
        };
        let has_parent = |s: &TaskStore, p: &str| {
            s.list_briefs_with_all_children_done(50)
                .unwrap()
                .iter()
                .any(|b| b.task_id == p)
        };

        let parent = mk("parent");
        s.set_brief_field(&parent, "assignee", "agt_planner")
            .unwrap();
        s.set_board_status(&parent, "in_progress").unwrap();
        let c1 = mk("c1");
        let c2 = mk("c2");
        s.link_subbrief(&parent, &c1).unwrap();
        s.link_subbrief(&parent, &c2).unwrap();

        // Children unfinished → not surfaced.
        assert!(!has_parent(&s, &parent));

        // Finish c1 only → still not (c2 active).
        s.set_brief_field(&c1, "assignee", "agt_work").unwrap();
        for st in ["todo", "in_progress"] {
            s.set_board_status(&c1, st).unwrap();
        }
        move_to_review(&s, &c1);
        s.set_board_status(&c1, "done").unwrap();
        assert!(!has_parent(&s, &parent));

        // Cancel c2 (terminal counts as finished) → now surfaced.
        s.set_board_status(&c2, "cancelled").unwrap();
        assert!(has_parent(&s, &parent));

        // A childless Brief never appears.
        let solo = mk("solo");
        move_to_progress(&s, &solo);
        assert!(!has_parent(&s, &solo));

        // Once the parent itself is done, it drops off.
        move_to_review(&s, &parent);
        s.set_board_status(&parent, "done").unwrap();
        assert!(!has_parent(&s, &parent));
    }

    #[test]
    fn phase2_campaign_and_mandate_progress_counts_by_column() {
        let s = store();
        let mk = |t: &str| {
            s.create(
                t,
                "flows/none.sol",
                "{}",
                "subj",
                RetryPolicy::None,
                0,
                None,
                None,
            )
            .unwrap()
        };
        let b1 = mk("b1");
        let b2 = mk("b2");
        let b3 = mk("b3");
        s.set_brief_field(&b1, "campaign", "camp_1").unwrap();
        s.set_brief_field(&b2, "campaign", "camp_1").unwrap();
        s.set_brief_field(&b3, "campaign", "camp_2").unwrap();
        s.set_brief_field(&b1, "mandate", "mand_1").unwrap();
        // b1 backlog, b2 todo (camp_1); b3 backlog (camp_2).
        s.set_board_status(&b2, "todo").unwrap();

        let c1: std::collections::HashMap<String, i64> = s
            .campaign_brief_counts("camp_1")
            .unwrap()
            .into_iter()
            .collect();
        assert_eq!(c1.get("backlog"), Some(&1));
        assert_eq!(c1.get("todo"), Some(&1));
        assert_eq!(c1.values().sum::<i64>(), 2);

        assert_eq!(
            s.campaign_brief_counts("camp_2").unwrap(),
            vec![("backlog".to_string(), 1)]
        );
        assert_eq!(
            s.mandate_brief_counts("mand_1").unwrap(),
            vec![("backlog".to_string(), 1)]
        );
        assert!(s.campaign_brief_counts("none").unwrap().is_empty());
    }

    /// File-backed open helper for the DB-hardening tests. We
    /// need an on-disk DB to confirm `journal_mode=WAL` (in-memory
    /// SQLite silently falls back to `memory`).
    fn file_store() -> (tempfile::TempDir, TaskStore) {
        let tmp = tempfile::tempdir().unwrap();
        let cfg = CoordinatorConfig {
            db_path: tmp.path().join("tasks.db"),
            max_list: 50,
            recovery_scan: false,
            retention: RetentionConfig::default(),
            ai_peer: None,
        };
        let s = TaskStore::open(&cfg).expect("open file store");
        (tmp, s)
    }

    #[test]
    fn open_sets_wal_mode() {
        let (_tmp, s) = file_store();
        let conn = s.conn.lock().unwrap();
        let mode: String = conn
            .query_row("PRAGMA journal_mode", [], |r| r.get(0))
            .unwrap();
        assert_eq!(mode.to_ascii_lowercase(), "wal");
    }

    #[test]
    fn open_enables_foreign_keys() {
        let (_tmp, s) = file_store();
        let conn = s.conn.lock().unwrap();
        let fk: i64 = conn
            .query_row("PRAGMA foreign_keys", [], |r| r.get(0))
            .unwrap();
        assert_eq!(fk, 1);
    }

    #[test]
    fn open_creates_migration_table_with_version_stamp() {
        let (_tmp, s) = file_store();
        let conn = s.conn.lock().unwrap();
        // The table itself.
        let cnt: i64 = conn
            .query_row(
                "SELECT COUNT(*) FROM sqlite_master \
                 WHERE type = 'table' AND name = '_relix_migrations'",
                [],
                |r| r.get(0),
            )
            .unwrap();
        assert_eq!(cnt, 1, "_relix_migrations table should exist");
        // And a version row, stamped at open.
        let v: i64 = conn
            .query_row("SELECT COUNT(*) FROM _relix_migrations", [], |r| r.get(0))
            .unwrap();
        assert!(v >= 1, "expected at least one migration version row");
    }

    // ── Chronicle retention ──────────────────────────────────

    /// Seed `events_per_task` events for `task_count` tasks, then
    /// flip the tasks into a terminal status so retention picks
    /// them up.
    fn seed_old_chronicle(s: &TaskStore, task_count: usize, events_per_task: usize, old_ts: i64) {
        for i in 0..task_count {
            let tid = mk(s, &format!("retention-task-{i}"), "flow.sol", "{}", "owner");
            // Pin events to an old ts so they fall under the cutoff.
            {
                let conn = s.conn.lock().unwrap();
                for k in 0..events_per_task {
                    conn.execute(
                        "INSERT INTO task_events (task_id, ts, event_type, payload) \
                         VALUES (?1, ?2, ?3, ?4)",
                        rusqlite::params![tid, old_ts + k as i64, "test.event", ""],
                    )
                    .unwrap();
                }
                conn.execute(
                    "UPDATE tasks SET status = 'completed', updated_at = ?2 WHERE task_id = ?1",
                    rusqlite::params![tid, old_ts],
                )
                .unwrap();
            }
        }
    }

    fn event_count(s: &TaskStore) -> i64 {
        let conn = s.conn.lock().unwrap();
        conn.query_row("SELECT COUNT(*) FROM task_events", [], |r| r.get(0))
            .unwrap()
    }

    #[test]
    fn retention_deletes_events_older_than_cutoff() {
        let s = store();
        let now = unix_secs();
        let old = now - 60 * 86_400;
        seed_old_chronicle(&s, 3, 4, old);
        // All 12 task_events rows present pre-run.
        assert_eq!(event_count(&s), 12);
        let cutoff = now - 30 * 86_400;
        let r = s.run_retention(cutoff, 10).unwrap();
        // The 12 old events go; 3 snapshot events are emitted in
        // their place. So we go from 12 → 3.
        assert_eq!(r.events_deleted, 12);
        assert_eq!(r.snapshots_emitted, 3);
        assert_eq!(r.tasks_compacted, 3);
        assert_eq!(event_count(&s), 3);
    }

    #[test]
    fn retention_skips_non_terminal_tasks_r5() {
        let s = store();
        let now = unix_secs();
        let old = now - 60 * 86_400;
        seed_old_chronicle(&s, 2, 3, old);
        // Flip one back to `running` — R5 says retention can't
        // touch active tasks.
        {
            let conn = s.conn.lock().unwrap();
            let running_id: String = conn
                .query_row("SELECT task_id FROM tasks LIMIT 1", [], |r| r.get(0))
                .unwrap();
            conn.execute(
                "UPDATE tasks SET status = 'running' WHERE task_id = ?1",
                rusqlite::params![running_id],
            )
            .unwrap();
        }
        let r = s.run_retention(now - 30 * 86_400, 10).unwrap();
        // Only the still-completed task gets compacted (3 events).
        assert_eq!(r.events_deleted, 3);
        assert_eq!(r.snapshots_emitted, 1);
        // The `running` task's 3 events survive untouched, plus
        // 1 snapshot from the completed task = 4.
        assert_eq!(event_count(&s), 4);
    }

    #[test]
    fn retention_emits_snapshot_event_with_summary_payload() {
        let s = store();
        let now = unix_secs();
        let old = now - 60 * 86_400;
        seed_old_chronicle(&s, 1, 5, old);
        let _ = s.run_retention(now - 30 * 86_400, 10).unwrap();
        // The remaining event is the snapshot. Confirm its shape.
        let conn = s.conn.lock().unwrap();
        let (event_type, payload_json): (String, Option<String>) = conn
            .query_row(
                "SELECT event_type, payload_json FROM task_events LIMIT 1",
                [],
                |r| Ok((r.get(0)?, r.get(1)?)),
            )
            .unwrap();
        assert_eq!(event_type, "task.snapshot");
        let pj = payload_json.expect("snapshot must carry payload_json");
        assert!(pj.contains("\"compacted_event_count\":5"), "got {pj}");
        assert!(pj.contains("\"final_status\":\"completed\""), "got {pj}");
        assert!(pj.contains("\"first_ts\":"), "got {pj}");
        assert!(pj.contains("\"last_ts\":"), "got {pj}");
    }

    #[test]
    fn retention_respects_limit_per_pass() {
        let s = store();
        let now = unix_secs();
        let old = now - 60 * 86_400;
        // Synthesise 2500 candidate events across one task so a
        // single 1000-row pass can't drain them; the loop must
        // run multiple passes.
        seed_old_chronicle(&s, 1, 2500, old);
        let r = s.run_retention(now - 30 * 86_400, 10).unwrap();
        assert_eq!(r.events_deleted, 2500);
        assert_eq!(r.snapshots_emitted, 1);
        // 2500 / 1000 = ceil 3 passes.
        assert!(
            r.passes_run >= 3,
            "expected ≥3 passes, got {}",
            r.passes_run
        );
        assert!(!r.stopped_at_pass_limit);
    }

    #[test]
    fn retention_honours_max_passes_cap() {
        let s = store();
        let now = unix_secs();
        let old = now - 60 * 86_400;
        seed_old_chronicle(&s, 1, 5000, old);
        // Cap at 2 passes — we should delete at most 2000 events
        // and the result must signal that we stopped early.
        let r = s.run_retention(now - 30 * 86_400, 2).unwrap();
        assert!(
            r.events_deleted <= MAX_ROWS_PER_RETENTION_PASS * 2,
            "deleted more than 2 passes' worth: {}",
            r.events_deleted
        );
        assert!(r.stopped_at_pass_limit);
    }

    #[test]
    fn retention_pass_is_a_noop_when_nothing_qualifies() {
        let s = store();
        let now = unix_secs();
        // No data at all.
        let r = s.run_retention(now - 30 * 86_400, 10).unwrap();
        assert_eq!(r.events_deleted, 0);
        assert_eq!(r.snapshots_emitted, 0);
        assert_eq!(r.tasks_compacted, 0);
        assert_eq!(r.passes_run, 0);
    }

    #[test]
    fn retention_does_not_re_compact_existing_snapshot_rows() {
        // Running retention twice in a row must NOT delete the
        // snapshot events emitted by the previous run. The
        // query explicitly excludes event_type='task.snapshot'.
        let s = store();
        let now = unix_secs();
        let old = now - 60 * 86_400;
        seed_old_chronicle(&s, 2, 3, old);
        let r1 = s.run_retention(now - 30 * 86_400, 10).unwrap();
        let mid_count = event_count(&s);
        assert_eq!(r1.snapshots_emitted, 2);
        assert_eq!(mid_count, 2); // two snapshots remain
        let r2 = s.run_retention(now - 30 * 86_400, 10).unwrap();
        assert_eq!(r2.events_deleted, 0, "snapshots survive a second pass");
        assert_eq!(r2.snapshots_emitted, 0);
        assert_eq!(event_count(&s), 2);
    }

    #[test]
    fn foreign_key_enforced_on_task_events() {
        // The `task_events.task_id` FK is declared in init_schema
        // but FK enforcement was off by default before the
        // hardening. With it on, inserting an event for a
        // non-existent task must be rejected.
        let (_tmp, s) = file_store();
        let conn = s.conn.lock().unwrap();
        let err = conn
            .execute(
                "INSERT INTO task_events (task_id, ts, event_type, payload) \
                 VALUES ('does-not-exist', 1, 'x', '')",
                [],
            )
            .expect_err("orphan event must be rejected");
        let m = err.to_string().to_ascii_lowercase();
        assert!(m.contains("foreign key"), "wrong err: {m}");
    }

    /// Test helper: create a task with the C1 defaults so we don't have
    /// to repeat the `RetryPolicy::None, 0, None` trailer at every call
    /// site.
    fn mk(s: &TaskStore, title: &str, flow: &str, params: &str, owner: &str) -> String {
        s.create(title, flow, params, owner, RetryPolicy::None, 0, None, None)
            .unwrap()
    }

