    #[test]
    fn create_with_origin_surface_roundtrips() {
        let s = store();
        for surface in ["chat", "dashboard", "cli", "channel", "flow-engine"] {
            let tid = s
                .create(
                    &format!("t-{surface}"),
                    "f",
                    "{}",
                    "o",
                    RetryPolicy::None,
                    0,
                    None,
                    Some(surface),
                )
                .unwrap();
            let v = s.get(&tid).unwrap().unwrap();
            assert_eq!(v.origin_surface.as_deref(), Some(surface));
        }
    }

    fn ctx(args: &[u8]) -> InvocationCtx {
        use relix_core::identity::VerifiedIdentity;
        use relix_core::types::{NodeId, RequestId, TraceId};
        InvocationCtx {
            caller: VerifiedIdentity {
                subject_id: NodeId::from_pubkey(b"x"),
                name: "x".into(),
                org_id: NodeId::from_pubkey(b"o"),
                groups: vec![],
                role: "".into(),
                clearance: "".into(),
                bundle_id: [0; 32],
            },
            trace_id: TraceId::new(),
            request_id: RequestId::new(),
            args: args.to_vec(),
            tenant_id: None,
        }
    }

    fn ctx_tenant(args: &[u8], tenant: &str) -> InvocationCtx {
        let mut c = ctx(args);
        c.tenant_id = Some(tenant.to_string());
        c
    }

    #[test]
    fn spine_handlers_isolate_briefs_per_tenant() {
        // The board / unassigned / detail capability handlers must scope
        // to the caller's Guild, so a cross-Guild Brief id is invisible.
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Board card", "subj", None, Some("m_a"), None, None)
            .unwrap();
        let b = s
            .create_brief(
                "globex",
                "Board card",
                "subj",
                None,
                Some("m_b"),
                None,
                None,
            )
            .unwrap();

        let cards = |out: HandlerOutcome| -> Vec<brief::BriefCard> {
            match out {
                HandlerOutcome::Ok(body) => serde_json::from_slice(&body).unwrap(),
                HandlerOutcome::Err(_) => panic!("handler returned an error"),
            }
        };
        // brief.board (todo) for acme shows a, not b.
        let acme_board = cards(handle_brief_board(&s, &ctx_tenant(b"todo|50", "acme")));
        assert!(acme_board.iter().any(|c| c.task_id == a));
        assert!(!acme_board.iter().any(|c| c.task_id == b));
        // brief.unassigned for globex shows b, not a.
        let globex_un = cards(handle_brief_unassigned(&s, &ctx_tenant(b"50", "globex")));
        assert!(globex_un.iter().any(|c| c.task_id == b));
        assert!(!globex_un.iter().any(|c| c.task_id == a));
        // brief.detail: acme can read a but NOT globex's b (not-found Err).
        assert!(matches!(
            handle_brief_detail(&s, &ctx_tenant(a.as_bytes(), "acme")),
            HandlerOutcome::Ok(_)
        ));
        assert!(matches!(
            handle_brief_detail(&s, &ctx_tenant(b.as_bytes(), "acme")),
            HandlerOutcome::Err(_)
        ));
    }

    #[test]
    fn create_brief_always_stamps_tenant() {
        // A Brief is always row-level stamped with its owning Guild; it is
        // never created as an unscoped row that would resolve to `default`.
        let s = TaskStore::in_memory().unwrap();
        let id = s
            .create_brief("acme", "Owned by acme", "subj", None, None, None, None)
            .unwrap();
        assert!(s.task_in_tenant(&id, "acme").unwrap());
        assert!(!s.task_in_tenant(&id, "globex").unwrap());
        // Crucially NOT visible to the default Guild — proving the stamp
        // actually ran (a missing stamp would COALESCE to 'default').
        assert!(!s.task_in_tenant(&id, "default").unwrap());
        // An empty tenant normalises to the default Guild.
        let d = s
            .create_brief("", "Owned by default", "subj", None, None, None, None)
            .unwrap();
        assert!(s.task_in_tenant(&d, "default").unwrap());
        assert!(!s.task_in_tenant(&d, "acme").unwrap());
    }

