    // §1.8: the `brief.dossier_author` handler is tenant-scoped on the owning
    // Brief exactly like the other Dossier surfaces — a cross-Guild author is
    // refused; the same-Guild author returns the authored JSON.
    #[test]
    fn brief_dossier_author_denied_across_tenant() {
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Acme", "subj", None, None, None, None)
            .unwrap();
        let arg = serde_json::json!({
            "task_id": a, "kind": "plan", "title": "P", "body": "b", "author": "founder"
        })
        .to_string();
        // Cross-Guild author is refused.
        assert!(matches!(
            handle_brief_dossier_author(&s, &ctx_tenant(arg.as_bytes(), "globex")),
            HandlerOutcome::Err(_)
        ));
        // Nothing was written.
        assert!(s.list_dossiers(&a).unwrap().is_empty());
        // Same-Guild author returns the authored JSON (create, rev 1).
        match handle_brief_dossier_author(&s, &ctx_tenant(arg.as_bytes(), "acme")) {
            HandlerOutcome::Ok(body) => {
                let v: serde_json::Value = serde_json::from_slice(&body).unwrap();
                assert_eq!(v["mode"], "create");
                assert_eq!(v["revision_number"], 1);
                assert!(v.get("stale").is_none());
            }
            HandlerOutcome::Err(_) => panic!("same-tenant author errored"),
        }
    }

    // §1.9 (thread interactions): open → list → respond happy path,
    // including the Chronicle mirror on both the open and the answer.
    #[test]
    fn brief_interaction_open_list_respond_happy_path() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Ship it?", "subj", None, None, None, None)
            .unwrap();
        let id = s
            .open_interaction(
                &b,
                "confirm",
                "operative-1",
                "Ship the v2 plan?",
                &["yes".into(), "no".into()],
            )
            .unwrap();
        // Opening mirrors into the Chronicle.
        let opened = s
            .query_events(&b, 0, 50, Some("brief.interaction_opened"), EventOrder::Asc)
            .unwrap();
        assert_eq!(opened.len(), 1);
        assert!(opened[0].payload.contains("Ship the v2 plan?"));

        // The card lists as open with its choices preserved.
        let listed = s.list_interactions(&b).unwrap();
        assert_eq!(listed.len(), 1);
        assert_eq!(listed[0].interaction_id, id);
        assert_eq!(listed[0].status, "open");
        assert_eq!(listed[0].choices, vec!["yes".to_string(), "no".to_string()]);
        assert!(listed[0].response.is_none());

        // Answer it; status + response land and the answer mirrors too.
        s.respond_interaction(&b, &id, "founder", "resolved", "yes — ship")
            .unwrap();
        let listed = s.list_interactions(&b).unwrap();
        assert_eq!(listed[0].status, "resolved");
        assert_eq!(listed[0].response.as_deref(), Some("yes — ship"));
        assert_eq!(listed[0].resolved_by.as_deref(), Some("founder"));
        assert!(listed[0].resolved_at.is_some());
        let answered = s
            .query_events(
                &b,
                0,
                50,
                Some("brief.interaction_resolved"),
                EventOrder::Asc,
            )
            .unwrap();
        assert_eq!(answered.len(), 1);
        assert!(answered[0].payload.contains("yes — ship"));
    }

    // A second answer to an already-answered card is a typed refusal,
    // not a silent overwrite (idempotent response contract).
    #[test]
    fn brief_interaction_duplicate_response_is_typed_refusal() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Q", "subj", None, None, None, None)
            .unwrap();
        let id = s
            .open_interaction(&b, "ask", "op", "Which region?", &[])
            .unwrap();
        s.respond_interaction(&b, &id, "founder", "resolved", "us-east")
            .unwrap();
        let again = s.respond_interaction(&b, &id, "founder", "resolved", "eu-west");
        assert!(matches!(again, Err(CoordinatorError::Invalid(_))));
        // The original answer is untouched.
        let listed = s.list_interactions(&b).unwrap();
        assert_eq!(listed[0].response.as_deref(), Some("us-east"));
    }

    // Open / list / respond are all scoped to the owning Brief's Guild:
    // a cross-Guild Brief or interaction id reads as not-found.
    #[test]
    fn brief_interaction_denied_across_tenant() {
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Acme", "subj", None, None, None, None)
            .unwrap();
        // Cross-tenant open is refused (empty choices arg `[]`).
        assert!(matches!(
            handle_brief_interaction_open(
                &s,
                &ctx_tenant(format!("{a}|confirm|op|[]|Proceed?").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        // Same-tenant open returns the id.
        let id = match handle_brief_interaction_open(
            &s,
            &ctx_tenant(format!("{a}|confirm|op|[]|Proceed?").as_bytes(), "acme"),
        ) {
            HandlerOutcome::Ok(body) => String::from_utf8(body).unwrap(),
            HandlerOutcome::Err(_) => panic!("interaction_open errored"),
        };
        // List + respond are isolated by the owning Brief's Guild.
        assert!(matches!(
            handle_brief_interactions(&s, &ctx_tenant(a.as_bytes(), "globex")),
            HandlerOutcome::Err(_)
        ));
        assert!(matches!(
            handle_brief_interaction_respond(
                &s,
                &ctx_tenant(format!("{a}|{id}|hacker|resolved|yes").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        // The card is still open for the owning Guild.
        let listed = s.list_interactions(&a).unwrap();
        assert_eq!(listed[0].status, "open");
    }

    // ── §1.8 Dossier (document) locking ──────────────────────────────────

    // A locked logical Dossier rejects a revision from anyone but the lock
    // owner (no silent overwrite); the owner can still author; unlock reopens.
    #[test]
    fn dossier_lock_blocks_other_author_then_unlock_allows() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Plan it", "subj", None, None, None, None)
            .unwrap();
        // Seed a first `plan` revision so the kind exists.
        let first = s
            .author_dossier(
                &b,
                "plan",
                "Plan v1",
                "the body",
                "alice",
                brief::DossierAuthorMode::Revise,
                None,
                None,
            )
            .unwrap();
        assert!(matches!(first, brief::DossierAuthorOutcome::Authored(_)));
        // alice locks the `plan` document.
        let locked = s
            .lock_dossier(&b, "plan", "alice", Some("drafting"))
            .unwrap();
        match locked {
            brief::DossierLockOutcome::Locked(l) => {
                assert_eq!(l.locked_by, "alice");
                assert_eq!(l.reason.as_deref(), Some("drafting"));
            }
            other => panic!("expected lock, got {other:?}"),
        }
        // It shows up in the lock list.
        let locks = s.list_dossier_locks(&b).unwrap();
        assert_eq!(locks.len(), 1);
        assert_eq!(locks[0].kind, "plan");
        assert_eq!(locks[0].locked_by, "alice");
        // bob's write is refused (locked), nothing written.
        let bob = s
            .author_dossier(
                &b,
                "plan",
                "Plan v2 (bob)",
                "sneaky",
                "bob",
                brief::DossierAuthorMode::Revise,
                None,
                None,
            )
            .unwrap();
        match bob {
            brief::DossierAuthorOutcome::Locked(l) => assert_eq!(l.locked_by, "alice"),
            other => panic!("expected locked refusal, got {other:?}"),
        }
        // Still one revision (bob's write did not land).
        let rev_count = s.list_dossiers(&b).unwrap().len();
        assert_eq!(rev_count, 1);
        // The owner (alice) can still author while holding the lock.
        let alice2 = s
            .author_dossier(
                &b,
                "plan",
                "Plan v2",
                "real update",
                "alice",
                brief::DossierAuthorMode::Revise,
                None,
                None,
            )
            .unwrap();
        assert!(matches!(alice2, brief::DossierAuthorOutcome::Authored(_)));
        // alice unlocks; now bob can author.
        let unlocked = s.unlock_dossier(&b, "plan", "alice").unwrap();
        match unlocked {
            brief::DossierUnlockOutcome::Unlocked(u) => {
                assert!(u.unlocked);
                assert_eq!(u.previously_locked_by.as_deref(), Some("alice"));
            }
            other => panic!("expected unlock, got {other:?}"),
        }
        assert!(s.list_dossier_locks(&b).unwrap().is_empty());
        let bob2 = s
            .author_dossier(
                &b,
                "plan",
                "Plan v3 (bob)",
                "now allowed",
                "bob",
                brief::DossierAuthorMode::Revise,
                None,
                None,
            )
            .unwrap();
        assert!(matches!(bob2, brief::DossierAuthorOutcome::Authored(_)));
    }

    // Lock/unlock are owner-or-nobody: a different subject conflicts; the
    // same owner re-lock is idempotent; unlock of an absent lock is a no-op.
    #[test]
    fn dossier_lock_conflict_and_idempotency() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Doc", "subj", None, None, None, None)
            .unwrap();
        // alice locks; a same-owner re-lock refreshes the reason (idempotent).
        s.lock_dossier(&b, "design", "alice", None).unwrap();
        let relock = s
            .lock_dossier(&b, "design", "alice", Some("now with reason"))
            .unwrap();
        match relock {
            brief::DossierLockOutcome::Locked(l) => {
                assert_eq!(l.reason.as_deref(), Some("now with reason"))
            }
            other => panic!("expected idempotent re-lock, got {other:?}"),
        }
        assert_eq!(s.list_dossier_locks(&b).unwrap().len(), 1);
        // bob cannot lock or unlock alice's lock.
        assert!(matches!(
            s.lock_dossier(&b, "design", "bob", None).unwrap(),
            brief::DossierLockOutcome::Conflict(_)
        ));
        assert!(matches!(
            s.unlock_dossier(&b, "design", "bob").unwrap(),
            brief::DossierUnlockOutcome::Conflict(_)
        ));
        // The lock is unchanged after the refused attempts.
        assert_eq!(s.list_dossier_locks(&b).unwrap()[0].locked_by, "alice");
        // alice unlocks; a second unlock is an idempotent no-op (no prior owner).
        assert!(matches!(
            s.unlock_dossier(&b, "design", "alice").unwrap(),
            brief::DossierUnlockOutcome::Unlocked(_)
        ));
        match s.unlock_dossier(&b, "design", "alice").unwrap() {
            brief::DossierUnlockOutcome::Unlocked(u) => {
                assert_eq!(u.previously_locked_by, None)
            }
            other => panic!("expected idempotent unlock, got {other:?}"),
        }
    }

    // Lock validates the kind token and bounds the reason; unlock validates too.
    #[test]
    fn dossier_lock_validates_inputs() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Doc", "subj", None, None, None, None)
            .unwrap();
        // Bad kind (space/pipe-hostile) is refused.
        assert!(matches!(
            s.lock_dossier(&b, "not a kind", "alice", None),
            Err(CoordinatorError::Invalid(_))
        ));
        // Empty subject is refused.
        assert!(matches!(
            s.lock_dossier(&b, "plan", "  ", None),
            Err(CoordinatorError::Invalid(_))
        ));
        // Over-long reason is refused (no write).
        let long = "x".repeat(MAX_DOSSIER_LOCK_REASON_LEN + 1);
        assert!(matches!(
            s.lock_dossier(&b, "plan", "alice", Some(&long)),
            Err(CoordinatorError::Invalid(_))
        ));
        assert!(s.list_dossier_locks(&b).unwrap().is_empty());
    }

    // Lock / unlock / list are tenant-scoped on the owning Brief: a cross-Guild
    // caller gets the same not-found shape as a missing Brief (no existence
    // leak), and cannot lock another Guild's Dossier.
    #[test]
    fn dossier_lock_denied_across_tenant() {
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Acme", "subj", None, None, None, None)
            .unwrap();
        // Cross-tenant lock / unlock / list all refuse at the handler boundary.
        assert!(matches!(
            handle_brief_dossier_lock(
                &s,
                &ctx_tenant(format!("{a}|plan|hacker|mine").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        assert!(matches!(
            handle_brief_dossier_unlock(
                &s,
                &ctx_tenant(format!("{a}|plan|hacker").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        assert!(matches!(
            handle_brief_dossier_locks(&s, &ctx_tenant(a.as_bytes(), "globex")),
            HandlerOutcome::Err(_)
        ));
        // Same-tenant lock works and is visible only to the owning Guild.
        assert!(matches!(
            handle_brief_dossier_lock(
                &s,
                &ctx_tenant(format!("{a}|plan|alice|").as_bytes(), "acme"),
            ),
            HandlerOutcome::Ok(_)
        ));
        assert_eq!(s.list_dossier_locks(&a).unwrap().len(), 1);
    }

    // ── §1.9 interaction cancel + idempotent create + continuation wake ───

    // Cancel closes an open card; re-cancel is idempotent; a cancelled card
    // can't then be answered; a decided card can't be cancelled.
    #[test]
    fn interaction_cancel_lifecycle() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Q", "subj", None, None, None, None)
            .unwrap();
        let id = s
            .open_interaction(&b, "ask", "op", "Which region?", &[])
            .unwrap();
        // Cancel the open card.
        s.cancel_interaction(&b, &id, "founder").unwrap();
        assert_eq!(s.list_interactions(&b).unwrap()[0].status, "cancelled");
        let ev = s
            .query_events(
                &b,
                0,
                50,
                Some("brief.interaction_cancelled"),
                EventOrder::Asc,
            )
            .unwrap();
        assert_eq!(ev.len(), 1);
        // Re-cancel is idempotent (success, no second event).
        s.cancel_interaction(&b, &id, "founder").unwrap();
        let ev = s
            .query_events(
                &b,
                0,
                50,
                Some("brief.interaction_cancelled"),
                EventOrder::Asc,
            )
            .unwrap();
        assert_eq!(ev.len(), 1, "idempotent re-cancel must not duplicate event");
        // A cancelled card can't be answered.
        assert!(matches!(
            s.respond_interaction(&b, &id, "founder", "resolved", "us-east"),
            Err(CoordinatorError::Invalid(_))
        ));
        // A decided (resolved) card can't be cancelled.
        let id2 = s.open_interaction(&b, "confirm", "op", "Go?", &[]).unwrap();
        s.respond_interaction(&b, &id2, "founder", "resolved", "yes")
            .unwrap();
        assert!(matches!(
            s.cancel_interaction(&b, &id2, "founder"),
            Err(CoordinatorError::Invalid(_))
        ));
    }

    // Idempotent create: the same (task_id, author, idempotency_key) returns the
    // existing card; a different key (or none) opens a new one.
    #[test]
    fn interaction_create_is_idempotent() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Q", "subj", None, None, None, None)
            .unwrap();
        let id1 = s
            .open_interaction_idem(&b, "ask", "op", "Region?", &[], Some("k1"))
            .unwrap();
        let id1b = s
            .open_interaction_idem(&b, "ask", "op", "Region? (retry)", &[], Some("k1"))
            .unwrap();
        assert_eq!(id1, id1b, "same key must return the existing card");
        // Only ONE card exists despite two creates.
        assert_eq!(s.list_interactions(&b).unwrap().len(), 1);
        // A different key opens a new card.
        let id2 = s
            .open_interaction_idem(&b, "ask", "op", "Region?", &[], Some("k2"))
            .unwrap();
        assert_ne!(id1, id2);
        // A different author with the same key is a different card.
        let id3 = s
            .open_interaction_idem(&b, "ask", "op2", "Region?", &[], Some("k1"))
            .unwrap();
        assert_ne!(id1, id3);
        // Keyless creates are never de-duplicated.
        let k1 = s.open_interaction(&b, "ask", "op", "X?", &[]).unwrap();
        let k2 = s.open_interaction(&b, "ask", "op", "X?", &[]).unwrap();
        assert_ne!(k1, k2);
    }

    // §1.9 continuation policy: answering OR cancelling a card nudges the
    // Brief's assignee to continue. With no assignee the hook records an honest
    // `brief.wakeup_skipped` note (proving it fired without inventing a wake).
    #[test]
    fn interaction_respond_and_cancel_offer_continuation_wake() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Q", "subj", None, None, None, None)
            .unwrap();
        let id = s.open_interaction(&b, "confirm", "op", "Go?", &[]).unwrap();
        s.respond_interaction(&b, &id, "founder", "resolved", "yes")
            .unwrap();
        let id2 = s.open_interaction(&b, "ask", "op", "Which?", &[]).unwrap();
        s.cancel_interaction(&b, &id2, "founder").unwrap();
        // The Brief has no assignee, so each continuation records a skipped note.
        let skipped = s
            .query_events(&b, 0, 50, Some("brief.wakeup_skipped"), EventOrder::Asc)
            .unwrap();
        assert_eq!(
            skipped.len(),
            2,
            "respond + cancel should each offer a continuation wake"
        );
    }

    // Cancel is tenant-scoped on the owning Brief (no existence leak).
    #[test]
    fn interaction_cancel_denied_across_tenant() {
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Acme", "subj", None, None, None, None)
            .unwrap();
        let id = s.open_interaction(&a, "ask", "op", "Q?", &[]).unwrap();
        assert!(matches!(
            handle_brief_interaction_cancel(
                &s,
                &ctx_tenant(format!("{a}|{id}|hacker").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        // Still open for the owning Guild.
        assert_eq!(s.list_interactions(&a).unwrap()[0].status, "open");
    }

    // §1.8 (approval-bound plan confirm): opening a plan confirm refuses
    // clearly when the Brief has no `plan` Dossier to bind to.
    #[test]
    fn plan_confirm_open_refuses_without_plan_dossier() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Needs a plan", "subj", None, None, None, None)
            .unwrap();
        // No `plan` Dossier yet — opening is a typed refusal, no card created.
        let out = s.open_plan_confirm(&b, "operative-1", "");
        assert!(matches!(out, Err(CoordinatorError::Invalid(_))));
        assert!(s.list_interactions(&b).unwrap().is_empty());
        // A Dossier of a *different* kind does not satisfy it either.
        s.add_dossier(&b, "design", "The Design", "boxes").unwrap();
        assert!(matches!(
            s.open_plan_confirm(&b, "operative-1", ""),
            Err(CoordinatorError::Invalid(_))
        ));
    }

    // §1.8: opening a plan confirm binds the CURRENT latest `plan` Dossier
    // revision (its id), records it in the interaction metadata, and
    // Chronicles the bound doc id so the approval thread is auditable.
    #[test]
    fn plan_confirm_open_binds_latest_plan_revision() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Plan it", "subj", None, None, None, None)
            .unwrap();
        s.add_dossier(&b, "plan", "Plan v1", "first").unwrap();
        let v2 = s.add_dossier(&b, "plan", "Plan v2", "second").unwrap();
        let id = s.open_plan_confirm(&b, "operative-1", "").unwrap();
        // The card is a confirm bound to the LATEST plan revision (v2), with
        // the bound kind recorded in its metadata.
        let listed = s.list_interactions(&b).unwrap();
        let card = listed.iter().find(|i| i.interaction_id == id).unwrap();
        assert_eq!(card.kind, "confirm");
        assert_eq!(card.status, "open");
        assert_eq!(card.bound_doc_id.as_deref(), Some(v2.as_str()));
        assert_eq!(card.bound_doc_kind.as_deref(), Some("plan"));
        // The bound doc id is mirrored into the Chronicle.
        let opened = s
            .query_events(
                &b,
                0,
                50,
                Some("brief.plan_confirm_opened"),
                EventOrder::Asc,
            )
            .unwrap();
        assert_eq!(opened.len(), 1);
        assert!(opened[0].payload.contains(&v2));
    }

    // §1.8: accepting the bound confirm SUCCEEDS while the latest plan is
    // unchanged; a duplicate accept is then a typed idempotent refusal.
    #[test]
    fn plan_confirm_accept_succeeds_when_plan_unchanged() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Plan it", "subj", None, None, None, None)
            .unwrap();
        s.add_dossier(&b, "plan", "Plan v1", "first").unwrap();
        let id = s.open_plan_confirm(&b, "operative-1", "Approve?").unwrap();
        s.respond_interaction(&b, &id, "founder", "resolved", "yes — ship")
            .unwrap();
        let listed = s.list_interactions(&b).unwrap();
        let card = listed.iter().find(|i| i.interaction_id == id).unwrap();
        assert_eq!(card.status, "resolved");
        assert_eq!(card.response.as_deref(), Some("yes — ship"));
        // A real approval event was recorded.
        assert_eq!(
            s.query_events(
                &b,
                0,
                50,
                Some("brief.interaction_resolved"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1
        );
        // Duplicate accept is a typed refusal, not a silent overwrite.
        assert!(matches!(
            s.respond_interaction(&b, &id, "founder", "resolved", "again"),
            Err(CoordinatorError::Invalid(_))
        ));
    }

    // §1.8: a newer `plan` Dossier attached AFTER the confirm opened makes
    // the old confirm STALE — accept refuses, the card expires, and NO
    // approved disposition is recorded against the superseded plan.
    #[test]
    fn plan_confirm_stale_after_new_plan_revision() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Plan it", "subj", None, None, None, None)
            .unwrap();
        s.add_dossier(&b, "plan", "Plan v1", "first").unwrap();
        let id = s.open_plan_confirm(&b, "operative-1", "").unwrap();
        // The plan changes out from under the open confirm.
        s.add_dossier(&b, "plan", "Plan v2", "second").unwrap();
        // Accepting is refused as stale.
        assert!(matches!(
            s.respond_interaction(&b, &id, "founder", "resolved", "yes"),
            Err(CoordinatorError::Invalid(_))
        ));
        // The card expired (not resolved); no approved success recorded.
        let listed = s.list_interactions(&b).unwrap();
        let card = listed.iter().find(|i| i.interaction_id == id).unwrap();
        assert_eq!(card.status, "expired");
        assert_eq!(card.response, None);
        assert!(
            s.query_events(
                &b,
                0,
                50,
                Some("brief.interaction_resolved"),
                EventOrder::Asc
            )
            .unwrap()
            .is_empty(),
            "a stale plan must never resolve as approved"
        );
        assert_eq!(
            s.query_events(
                &b,
                0,
                50,
                Some("brief.interaction_expired"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1
        );
    }

    // §1.8: the SAME plan-bound stale protection holds when the newer plan
    // revision is written through the NEW `author_dossier` path (not just
    // `add_dossier`). Authoring a fresh `plan` revision makes the open
    // plan-bound confirm stale; the accept refuses and never resolves approved.
    #[test]
    fn plan_confirm_stale_after_authored_plan_revision() {
        use brief::DossierAuthorMode;
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Plan it", "subj", None, None, None, None)
            .unwrap();
        let v1 = s.add_dossier(&b, "plan", "Plan v1", "first").unwrap();
        let id = s.open_plan_confirm(&b, "operative-1", "").unwrap();
        // The plan is revised through the governed author path (optimistic lock
        // satisfied: v1 is still latest at author time).
        s.author_dossier(
            &b,
            "plan",
            "Plan v2",
            "second",
            "founder",
            DossierAuthorMode::Revise,
            Some(&v1),
            None,
        )
        .unwrap();
        // Accepting the now-superseded confirm is refused as stale.
        assert!(matches!(
            s.respond_interaction(&b, &id, "founder", "resolved", "yes"),
            Err(CoordinatorError::Invalid(_))
        ));
        let listed = s.list_interactions(&b).unwrap();
        let card = listed.iter().find(|i| i.interaction_id == id).unwrap();
        assert_eq!(card.status, "expired");
        assert_eq!(card.response, None);
        assert!(
            s.query_events(
                &b,
                0,
                50,
                Some("brief.interaction_resolved"),
                EventOrder::Asc
            )
            .unwrap()
            .is_empty(),
            "a stale plan must never resolve as approved"
        );
    }

    // §1.8/§1.9 supersede-on-comment: commenting while a plan-bound confirm
    // is open supersedes/expires it (the operator answered by commenting); a
    // later accept is then a typed refusal.
    #[test]
    fn plan_confirm_superseded_by_comment() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Plan it", "subj", None, None, None, None)
            .unwrap();
        s.add_dossier(&b, "plan", "Plan v1", "first").unwrap();
        let id = s.open_plan_confirm(&b, "operative-1", "").unwrap();
        // The operator just comments instead of clicking.
        s.comment_on_brief(&b, "founder", "let's tweak step 2 first")
            .unwrap();
        let listed = s.list_interactions(&b).unwrap();
        let card = listed.iter().find(|i| i.interaction_id == id).unwrap();
        assert_eq!(card.status, "expired");
        assert_eq!(
            s.query_events(
                &b,
                0,
                50,
                Some("brief.interaction_expired"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1
        );
        // A later accept is a typed (idempotent) refusal — the comment thread
        // moved past it; it must not resolve as approved.
        assert!(matches!(
            s.respond_interaction(&b, &id, "founder", "resolved", "yes"),
            Err(CoordinatorError::Invalid(_))
        ));
    }

    // §1.8: a PLAIN confirm (not bound to a Dossier) is unaffected by plan
    // updates and supersede-on-comment — the existing behavior is preserved.
    #[test]
    fn plain_confirm_unaffected_by_plan_update_and_comment() {
        let s = TaskStore::in_memory().unwrap();
        let b = s
            .create_brief("acme", "Ship?", "subj", None, None, None, None)
            .unwrap();
        let id = s
            .open_interaction(&b, "confirm", "operative-1", "Proceed?", &[])
            .unwrap();
        // Plain confirms carry no Dossier binding.
        let card = s.list_interactions(&b).unwrap().remove(0);
        assert_eq!(card.bound_doc_id, None);
        assert_eq!(card.bound_doc_kind, None);
        // A plan churn + a comment do NOT touch it.
        s.add_dossier(&b, "plan", "Plan v1", "first").unwrap();
        s.add_dossier(&b, "plan", "Plan v2", "second").unwrap();
        s.comment_on_brief(&b, "founder", "fyi").unwrap();
        assert_eq!(s.list_interactions(&b).unwrap()[0].status, "open");
        // And it still accepts normally.
        s.respond_interaction(&b, &id, "founder", "resolved", "yes")
            .unwrap();
        assert_eq!(s.list_interactions(&b).unwrap()[0].status, "resolved");
    }

    // §1.8 + GROUP 6 (tenant isolation): a plan confirm cannot be opened,
    // bound, or accepted across Guilds — a cross-Guild Brief/card reads as
    // not-found (no existence leak), same convention as plain interactions.
    #[test]
    fn plan_confirm_denied_across_tenant() {
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Acme", "subj", None, None, None, None)
            .unwrap();
        s.add_dossier(&a, "plan", "The Plan", "body").unwrap();
        // Cross-tenant open is refused.
        assert!(matches!(
            handle_brief_plan_confirm_open(
                &s,
                &ctx_tenant(format!("{a}|op|").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        // Same-tenant open returns the bound card id.
        let id = match handle_brief_plan_confirm_open(
            &s,
            &ctx_tenant(format!("{a}|op|").as_bytes(), "acme"),
        ) {
            HandlerOutcome::Ok(body) => String::from_utf8(body).unwrap(),
            HandlerOutcome::Err(_) => panic!("plan_confirm_open errored"),
        };
        // Cross-tenant accept is refused (not-found on the owning Brief).
        assert!(matches!(
            handle_brief_interaction_respond(
                &s,
                &ctx_tenant(format!("{a}|{id}|hacker|resolved|yes").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        // Still open for the owning Guild.
        let card = s
            .list_interactions(&a)
            .unwrap()
            .into_iter()
            .find(|i| i.interaction_id == id)
            .unwrap();
        assert_eq!(card.status, "open");
    }

    // ── Plan package (§1.7/§1.8/§3.1): tie bound-plan approval into the
    //    decomposition trigger. Opening a plan package creates a plan Dossier +
    //    a suggest_tasks proposal + an approval-bound confirm linked to both;
    //    accepting the confirm materializes the linked proposal exactly once. ──

    // Helper: open a plan package on `parent` with the given child titles.
    fn open_pkg(s: &TaskStore, parent: &str, titles: &[&str]) -> brief::PlanPackage {
        let children: Vec<brief::ChildSpec> = titles
            .iter()
            .map(|t| brief::ChildSpec {
                title: (*t).into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            })
            .collect();
        s.open_plan_package(
            parent,
            "operative-1",
            "Plan",
            "the plan body",
            "Break it down",
            &children,
            "",
        )
        .unwrap()
    }

    // Opening a plan package creates exactly one plan Dossier, one linked
    // suggest_tasks card, and one confirm bound to BOTH (the plan revision +
    // the proposal interaction id).
    #[test]
    fn plan_package_open_creates_plan_suggestion_and_bound_confirm() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg(&s, &parent, &["A", "B"]);
        // Exactly one `plan` Dossier, and it is the bound revision.
        let docs = s.list_dossiers(&parent).unwrap();
        assert_eq!(docs.iter().filter(|d| d.kind == "plan").count(), 1);
        assert_eq!(docs[0].doc_id, pkg.plan_doc_id);
        // Exactly one suggest_tasks card + one confirm card.
        let cards = s.list_interactions(&parent).unwrap();
        let suggests: Vec<_> = cards.iter().filter(|c| c.kind == "suggest_tasks").collect();
        let confirms: Vec<_> = cards.iter().filter(|c| c.kind == "confirm").collect();
        assert_eq!(suggests.len(), 1);
        assert_eq!(confirms.len(), 1);
        assert_eq!(suggests[0].interaction_id, pkg.suggestion_id);
        assert_eq!(suggests[0].proposal.as_ref().unwrap().children.len(), 2);
        // The confirm is bound to the exact plan revision AND linked to the
        // exact proposal.
        let confirm = confirms[0];
        assert_eq!(confirm.interaction_id, pkg.confirm_id);
        assert_eq!(confirm.bound_doc_kind.as_deref(), Some("plan"));
        assert_eq!(
            confirm.bound_doc_id.as_deref(),
            Some(pkg.plan_doc_id.as_str())
        );
        assert_eq!(
            confirm.bound_interaction_id.as_deref(),
            Some(pkg.suggestion_id.as_str())
        );
        // The opening is chronicled.
        assert_eq!(
            s.query_events(
                &parent,
                0,
                50,
                Some("brief.plan_package_opened"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1
        );
    }

    // Accepting the linked confirm materializes the children exactly once and
    // resolves BOTH the confirm and the linked suggestion appropriately.
    #[test]
    fn plan_confirm_accept_materializes_and_resolves_both() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg(&s, &parent, &["A", "B", "C"]);
        let res = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                true,
                &[],
            )
            .unwrap();
        assert_eq!(res.outcome, "approved");
        assert_eq!(res.created.len(), 3);
        assert_eq!(res.suggestion_id, pkg.suggestion_id);
        // Real, linked Sub-briefs — exactly the created set (no orphans).
        let subs = s.list_subbriefs(&parent).unwrap();
        assert_eq!(subs.len(), 3);
        for c in &res.created {
            assert!(subs.contains(c));
            assert!(s.get(c).unwrap().is_some());
        }
        // Both cards resolved; materialization + approval chronicled once.
        let cards = s.list_interactions(&parent).unwrap();
        let suggestion = cards
            .iter()
            .find(|c| c.interaction_id == pkg.suggestion_id)
            .unwrap();
        let confirm = cards
            .iter()
            .find(|c| c.interaction_id == pkg.confirm_id)
            .unwrap();
        assert_eq!(suggestion.status, "resolved");
        assert_eq!(confirm.status, "resolved");
        assert_eq!(
            confirm.response.as_deref(),
            Some(res.created.join(",").as_str())
        );
        assert_eq!(materialized_count(&s, &parent), 1);
        assert_eq!(
            s.query_events(
                &parent,
                0,
                50,
                Some("brief.plan_confirm_approved"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1
        );
    }

    // Accepting twice does not duplicate children and leaves no orphans — the
    // second accept is idempotent (`already_approved`) and returns the SAME ids.
    #[test]
    fn plan_confirm_accept_twice_is_idempotent() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg(&s, &parent, &["A", "B"]);
        let first = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                true,
                &[],
            )
            .unwrap();
        let second = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                true,
                &[],
            )
            .unwrap();
        assert_eq!(first.outcome, "approved");
        assert_eq!(second.outcome, "already_approved");
        assert_eq!(first.created, second.created, "same ids on re-accept");
        // No duplicate children, and every Sub-brief is one we created.
        let subs = s.list_subbriefs(&parent).unwrap();
        assert_eq!(subs.len(), 2, "no duplicate children");
        for c in &subs {
            assert!(first.created.contains(c), "no orphan child {c}");
        }
        assert_eq!(materialized_count(&s, &parent), 1);
        // Only one approval event despite two accepts.
        assert_eq!(
            s.query_events(
                &parent,
                0,
                50,
                Some("brief.plan_confirm_approved"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1
        );
    }

    // Rejecting the confirm rejects the linked suggestion and creates no
    // children.
    #[test]
    fn plan_confirm_reject_closes_linked_suggestion_no_children() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg(&s, &parent, &["A", "B"]);
        let res = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                false,
                &[],
            )
            .unwrap();
        assert_eq!(res.outcome, "rejected");
        assert!(res.created.is_empty());
        assert!(s.list_subbriefs(&parent).unwrap().is_empty(), "no children");
        let cards = s.list_interactions(&parent).unwrap();
        let suggestion = cards
            .iter()
            .find(|c| c.interaction_id == pkg.suggestion_id)
            .unwrap();
        let confirm = cards
            .iter()
            .find(|c| c.interaction_id == pkg.confirm_id)
            .unwrap();
        assert_eq!(confirm.status, "rejected");
        assert_eq!(
            suggestion.status, "rejected",
            "linked suggestion closed too"
        );
        assert_eq!(materialized_count(&s, &parent), 0);
    }

    // A newer `plan` Dossier before accept expires the confirm and does NOT
    // materialize the linked suggestion (no approval against a superseded plan).
    #[test]
    fn plan_confirm_stale_plan_expires_and_does_not_materialize() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg(&s, &parent, &["A", "B"]);
        // The plan changes (a newer `plan` Dossier) before the operator accepts.
        s.add_dossier(&parent, "plan", "Plan v2", "rewritten")
            .unwrap();
        let err = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                true,
                &[],
            )
            .unwrap_err();
        assert!(
            matches!(err, CoordinatorError::Invalid(_)),
            "stale ⇒ refused"
        );
        // The confirm expired; the suggestion is untouched (still open, no claim,
        // no children).
        let cards = s.list_interactions(&parent).unwrap();
        let confirm = cards
            .iter()
            .find(|c| c.interaction_id == pkg.confirm_id)
            .unwrap();
        let suggestion = cards
            .iter()
            .find(|c| c.interaction_id == pkg.suggestion_id)
            .unwrap();
        assert_eq!(confirm.status, "expired");
        assert_eq!(
            suggestion.status, "open",
            "linked suggestion not materialized"
        );
        assert!(s.list_subbriefs(&parent).unwrap().is_empty(), "no children");
        assert!(
            decomp_claim(&s, &parent, &pkg.suggestion_id).is_none(),
            "no claim"
        );
    }

    // A comment that supersedes the bound confirm (flipping it to `expired`)
    // also blocks materialization through the plan-confirm accept path.
    #[test]
    fn plan_confirm_comment_supersede_blocks_materialization() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg(&s, &parent, &["A"]);
        // A comment supersedes any OPEN plan-bound confirm (§1.8) → `expired`.
        s.comment_on_brief(&parent, "founder", "let's hold off")
            .unwrap();
        let confirm = s
            .list_interactions(&parent)
            .unwrap()
            .into_iter()
            .find(|c| c.interaction_id == pkg.confirm_id)
            .unwrap();
        assert_eq!(confirm.status, "expired", "comment supersedes the confirm");
        // Accepting the now-expired confirm refuses and never materializes.
        let err = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                true,
                &[],
            )
            .unwrap_err();
        assert!(matches!(err, CoordinatorError::Invalid(_)));
        assert!(s.list_subbriefs(&parent).unwrap().is_empty());
    }

    // `after` dependencies still wire as Snags after accept through the plan
    // confirm (the same intra-proposal edges as a standalone suggestion accept).
    #[test]
    fn plan_confirm_accept_wires_after_dependencies() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        // Child #1 depends on #0 (a backward edge).
        let children = vec![
            brief::ChildSpec {
                title: "First".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            },
            brief::ChildSpec {
                title: "Second".into(),
                priority: None,
                after: Some(0),
                assignee_agent_id: None,
                assignee_role: None,
            },
        ];
        let pkg = s
            .open_plan_package(&parent, "op", "Plan", "body", "ordered plan", &children, "")
            .unwrap();
        let res = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                true,
                &[],
            )
            .unwrap();
        assert_eq!(res.created.len(), 2);
        // The second child is `blocked_on` the first.
        let snags = s.list_snags(&res.created[1]).unwrap();
        assert!(
            snags.contains(&res.created[0]),
            "after edge wired as a Snag"
        );
    }

    // If the linked suggestion already materialized/closed (e.g. accepted
    // directly), rejecting the confirm does NOT corrupt it — the confirm is
    // rejected and the outcome is honest.
    #[test]
    fn plan_confirm_reject_after_suggestion_materialized_is_honest() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg(&s, &parent, &["A", "B"]);
        // The linked suggestion is accepted directly (a separate route).
        let created = s
            .respond_suggestion(
                "acme",
                "subj",
                &parent,
                &pkg.suggestion_id,
                "founder",
                true,
                &[],
            )
            .unwrap();
        assert_eq!(created.len(), 2);
        // Rejecting the confirm now is honest: confirm rejected, suggestion left
        // intact (still resolved, children unharmed).
        let res = s
            .respond_plan_confirm(
                "acme",
                "subj",
                &parent,
                &pkg.confirm_id,
                "founder",
                false,
                &[],
            )
            .unwrap();
        assert_eq!(res.outcome, "rejected_proposal_already_closed");
        let cards = s.list_interactions(&parent).unwrap();
        let suggestion = cards
            .iter()
            .find(|c| c.interaction_id == pkg.suggestion_id)
            .unwrap();
        let confirm = cards
            .iter()
            .find(|c| c.interaction_id == pkg.confirm_id)
            .unwrap();
        assert_eq!(confirm.status, "rejected");
        assert_eq!(
            suggestion.status, "resolved",
            "materialized suggestion untouched"
        );
        assert_eq!(
            s.list_subbriefs(&parent).unwrap().len(),
            2,
            "children intact"
        );
    }

