    // §1.9 (suggest_tasks): accepting a suggestion materializes the
    // proposed children as real Sub-briefs, links them to the parent, and
    // resolves the card with the created ids + a Chronicle entry.
    #[test]
    fn brief_suggestion_accept_materializes_children() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Parent epic", "subj", None, None, None, None)
            .unwrap();
        let children = vec![
            brief::ChildSpec {
                title: "Design the API".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            },
            brief::ChildSpec {
                title: "Wire the store".into(),
                priority: Some("high".into()),
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            },
        ];
        let id = s
            .open_suggestion(&parent, "operative-1", "Break this epic down", &children)
            .unwrap();
        // The opening is chronicled and the card lists with its proposal.
        let opened = s
            .query_events(
                &parent,
                0,
                50,
                Some("brief.suggestion_opened"),
                EventOrder::Asc,
            )
            .unwrap();
        assert_eq!(opened.len(), 1);
        let listed = s.list_interactions(&parent).unwrap();
        assert_eq!(listed[0].kind, "suggest_tasks");
        assert_eq!(listed[0].proposal.as_ref().unwrap().children.len(), 2);

        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        assert_eq!(created.len(), 2, "two children created");
        // Both are real Briefs, linked as Sub-briefs of the parent.
        let subs = s.list_subbriefs(&parent).unwrap();
        assert_eq!(subs.len(), 2);
        for c in &created {
            assert!(subs.contains(c), "{c} must be a Sub-brief of the parent");
            assert!(
                s.get(c).unwrap().is_some(),
                "{c} must exist as a real Brief"
            );
        }
        // The high-priority child kept its priority.
        let hi = s.brief_fields(&created[1]).unwrap().unwrap();
        assert_eq!(hi.priority, "high");
        // The card is resolved with the created ids; materialization chronicled.
        let listed = s.list_interactions(&parent).unwrap();
        assert_eq!(listed[0].status, "resolved");
        assert_eq!(
            listed[0].response.as_deref(),
            Some(created.join(",").as_str())
        );
        let mat = s
            .query_events(
                &parent,
                0,
                50,
                Some("brief.suggestion_materialized"),
                EventOrder::Asc,
            )
            .unwrap();
        assert_eq!(mat.len(), 1);
    }

    // Accepted children inherit the parent's SAFE spine context
    // (Mandate/Campaign/reviewer) but NOT its assignee (governance-gated).
    #[test]
    fn brief_suggestion_children_inherit_parent_context() {
        let s = TaskStore::in_memory().unwrap();
        // Parent carries a full spine context + an assignee.
        let parent = s
            .create_brief(
                "acme",
                "Parent epic",
                "subj",
                Some("agent_assignee"),
                Some("mandate_x"),
                Some("campaign_y"),
                None,
            )
            .unwrap();
        s.set_brief_field(&parent, "reviewer", "agent_reviewer")
            .unwrap();

        let children = vec![
            brief::ChildSpec {
                title: "Child one".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            },
            brief::ChildSpec {
                title: "Child two".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            },
        ];
        let id = s
            .open_suggestion(&parent, "operative-1", "Break it down", &children)
            .unwrap();
        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        assert_eq!(created.len(), 2);
        for c in &created {
            let f = s.brief_fields(c).unwrap().unwrap();
            assert_eq!(
                f.mandate_id.as_deref(),
                Some("mandate_x"),
                "mandate inherited"
            );
            assert_eq!(
                f.campaign_id.as_deref(),
                Some("campaign_y"),
                "campaign inherited"
            );
            assert_eq!(
                f.reviewer_agent_id.as_deref(),
                Some("agent_reviewer"),
                "reviewer inherited"
            );
            // Assignee is NOT inherited — assignment stays governance-gated.
            assert_eq!(f.assignee_agent_id, None, "assignee must NOT be inherited");
        }
        // The materialization Chronicle names the inherited context.
        let mat = s
            .query_events(
                &parent,
                0,
                50,
                Some("brief.suggestion_materialized"),
                EventOrder::Asc,
            )
            .unwrap();
        assert_eq!(mat.len(), 1);
        assert!(
            mat[0].payload.contains("mandate+campaign+reviewer"),
            "Chronicle must name the inherited context: {}",
            mat[0].payload
        );
    }

    // §1.9 (governed assignee hints): accept applies the pre-validated
    // per-child assignees — one child assigned, one left unassigned — and
    // the Chronicle names the split. (Resolution + the assign-Key gate run
    // in the wire handler before this call; here we pin the materialization
    // that applies the validated result.)
    #[test]
    fn brief_suggestion_accept_applies_resolved_assignees() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Parent", "subj", None, None, None, None)
            .unwrap();
        let children = vec![
            brief::ChildSpec {
                title: "Assigned child".into(),
                priority: None,
                after: None,
                assignee_agent_id: Some("agt_eng_1".into()),
                assignee_role: None,
            },
            brief::ChildSpec {
                title: "Unassigned child".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            },
        ];
        let id = s
            .open_suggestion(&parent, "op", "Plan with one assignment", &children)
            .unwrap();
        // The handler would resolve these; here we pass the validated result.
        let resolved = vec![Some("agt_eng_1".to_string()), None];
        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &resolved)
            .unwrap();
        assert_eq!(created.len(), 2);
        // Child #0 carries the assignee; child #1 opens unassigned.
        let f0 = s.brief_fields(&created[0]).unwrap().unwrap();
        assert_eq!(f0.assignee_agent_id.as_deref(), Some("agt_eng_1"));
        let f1 = s.brief_fields(&created[1]).unwrap().unwrap();
        assert_eq!(f1.assignee_agent_id, None, "second child stays unassigned");
        // The assigned child records a `brief.assigned` Chronicle event.
        let assigned_events = s
            .query_events(&created[0], 0, 50, Some("brief.assigned"), EventOrder::Asc)
            .unwrap();
        assert_eq!(assigned_events.len(), 1, "assigned child is chronicled");
        // The parent's materialization Chronicle names assigned vs needs-assignment.
        let mat = s
            .query_events(
                &parent,
                0,
                50,
                Some("brief.suggestion_materialized"),
                EventOrder::Asc,
            )
            .unwrap();
        assert!(
            mat[0].payload.contains("1 assigned, 1 need assignment"),
            "Chronicle must name the assignment split: {}",
            mat[0].payload
        );
    }

    // An empty `resolved_assignees` slice (the no-hint path) leaves every
