    // Tenant scoping: a cross-Guild Brief id is invisible to suggest open /
    // respond (no existence leak); the same-Guild caller succeeds.
    #[test]
    fn brief_suggestion_denied_across_tenant() {
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Acme", "subj", None, None, None, None)
            .unwrap();
        let open_arg = serde_json::json!({
            "task_id": a,
            "author": "op",
            "summary": "Plan",
            "children": [{ "title": "A" }],
        });
        let open_bytes = serde_json::to_vec(&open_arg).unwrap();
        // Cross-tenant open is refused.
        assert!(matches!(
            handle_brief_suggest_open(&s, &ctx_tenant(&open_bytes, "globex")),
            HandlerOutcome::Err(_)
        ));
        // Same-tenant open returns the id.
        let id = match handle_brief_suggest_open(&s, &ctx_tenant(&open_bytes, "acme")) {
            HandlerOutcome::Ok(body) => String::from_utf8(body).unwrap(),
            HandlerOutcome::Err(_) => panic!("suggest_open errored"),
        };
        // Cross-tenant accept is refused and creates nothing.
        assert!(matches!(
            handle_brief_suggest_respond(
                &s,
                None,
                &ctx_tenant(format!("{a}|{id}|hacker|accept").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        assert!(s.list_subbriefs(&a).unwrap().is_empty());
        // Same-tenant accept works and reports the created ids.
        let out = handle_brief_suggest_respond(
            &s,
            None,
            &ctx_tenant(format!("{a}|{id}|founder|accept").as_bytes(), "acme"),
        );
        let body = match out {
            HandlerOutcome::Ok(b) => b,
            HandlerOutcome::Err(_) => panic!("suggest_respond errored"),
        };
        let v: serde_json::Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(v["created"].as_array().unwrap().len(), 1);
        assert_eq!(s.list_subbriefs(&a).unwrap().len(), 1);
    }

    // An operator-role ctx in `tenant`: the Founder/operator is sovereign
    // over assignment, so the assign-Key check is bypassed — the resolver
    // still enforces same-Guild + active explicitly.
    fn ctx_op_tenant(args: &[u8], tenant: &str) -> InvocationCtx {
        let mut c = ctx_tenant(args, tenant);
        c.caller.role = "operator".into();
        c
    }

    // §1.9 (governed assignee hints) — end to end through the wire handler:
    // a child carrying a role hint is resolved + gated and assigned on
    // accept; a sibling with no hint opens unassigned.
    #[test]
    fn brief_suggestion_handler_assigns_via_role_hint() {
        let s = TaskStore::in_memory().unwrap();
        let astore = agent::AgentStore::in_memory().unwrap();
        // One active engineer in the Guild — the role hint resolves to it.
        let (eng, _) = astore
            .ensure_starter_operative("engineer", "Eng (local · echo)", "Engineer", "echo", "acme")
            .unwrap();
        let parent = s
            .create_brief("acme", "Parent", "subj", None, None, None, None)
            .unwrap();
        let open_arg = serde_json::json!({
            "task_id": parent,
            "author": "op",
            "summary": "Plan with a role assignment",
            "children": [
                { "title": "Assigned", "assignee_role": "engineer" },
                { "title": "Plain" },
            ],
        });
        let open_bytes = serde_json::to_vec(&open_arg).unwrap();
        let id = match handle_brief_suggest_open(&s, &ctx_op_tenant(&open_bytes, "acme")) {
            HandlerOutcome::Ok(b) => String::from_utf8(b).unwrap(),
            HandlerOutcome::Err(e) => panic!("open: {} {}", e.kind, e.cause),
        };
        let out = handle_brief_suggest_respond(
            &s,
            Some(&astore),
            &ctx_op_tenant(format!("{parent}|{id}|founder|accept").as_bytes(), "acme"),
        );
        let body = match out {
            HandlerOutcome::Ok(b) => b,
            HandlerOutcome::Err(e) => panic!("accept: {} {}", e.kind, e.cause),
        };
        let v: serde_json::Value = serde_json::from_slice(&body).unwrap();
        let created: Vec<String> = v["created"]
            .as_array()
            .unwrap()
            .iter()
            .map(|x| x.as_str().unwrap().to_string())
            .collect();
        assert_eq!(created.len(), 2);
        // First child assigned to the resolved engineer; second unassigned.
        assert_eq!(
            s.brief_fields(&created[0])
                .unwrap()
                .unwrap()
                .assignee_agent_id
                .as_deref(),
            Some(eng.as_str())
        );
        assert_eq!(
            s.brief_fields(&created[1])
                .unwrap()
                .unwrap()
                .assignee_agent_id,
            None
        );
    }

    // §1.9: an unhonourable hint (a role with no active Operative) refuses
    // the WHOLE accept — no child is created (no partial materialization)
    // and the card stays open for a retry.
    #[test]
    fn brief_suggestion_handler_invalid_hint_refused_no_partial() {
        let s = TaskStore::in_memory().unwrap();
        let astore = agent::AgentStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Parent", "subj", None, None, None, None)
            .unwrap();
        let open_arg = serde_json::json!({
            "task_id": parent,
            "author": "op",
            "summary": "Plan",
            "children": [
                { "title": "A" },
                { "title": "B", "assignee_role": "ghost" },
            ],
        });
        let open_bytes = serde_json::to_vec(&open_arg).unwrap();
        let id = match handle_brief_suggest_open(&s, &ctx_op_tenant(&open_bytes, "acme")) {
            HandlerOutcome::Ok(b) => String::from_utf8(b).unwrap(),
            HandlerOutcome::Err(e) => panic!("open: {} {}", e.kind, e.cause),
        };
        let out = handle_brief_suggest_respond(
            &s,
            Some(&astore),
            &ctx_op_tenant(format!("{parent}|{id}|founder|accept").as_bytes(), "acme"),
        );
        assert!(
            matches!(out, HandlerOutcome::Err(_)),
            "an unhonourable hint must refuse the accept"
        );
        // No child created, and the card is still open (a retry is possible).
        assert!(
            s.list_subbriefs(&parent).unwrap().is_empty(),
            "no partial creation"
        );
        let listed = s.list_interactions(&parent).unwrap();
        assert_eq!(listed[0].status, "open", "card stays open after refusal");
    }

    // ── Plan package wire handlers (§1.7/§1.8/§3.1) ──

    // Helper: open a plan package through the wire handler, returning the pkg.
    fn open_pkg_handler(
        s: &TaskStore,
        parent: &str,
        tenant: &str,
        children: serde_json::Value,
    ) -> brief::PlanPackage {
        let arg = serde_json::json!({
            "task_id": parent,
            "author": "op",
            "plan_title": "Plan",
            "plan_body": "the plan body",
            "summary": "Break it down",
            "children": children,
        });
        let bytes = serde_json::to_vec(&arg).unwrap();
        match handle_brief_plan_package_open(s, &ctx_op_tenant(&bytes, tenant)) {
            HandlerOutcome::Ok(b) => serde_json::from_slice(&b).unwrap(),
            HandlerOutcome::Err(e) => panic!("plan_package_open: {} {}", e.kind, e.cause),
        }
    }

    // End-to-end through the wire handler: a plan package accept resolves the
    // confirm and materializes the linked proposal exactly once, returning a
    // typed outcome + the created ids.
    #[test]
    fn plan_confirm_handler_accept_materializes() {
        let s = TaskStore::in_memory().unwrap();
        let astore = agent::AgentStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg_handler(
            &s,
            &parent,
            "acme",
            serde_json::json!([{ "title": "A" }, { "title": "B" }]),
        );
        let out = handle_brief_plan_confirm_respond(
            &s,
            Some(&astore),
            &ctx_op_tenant(
                format!("{parent}|{}|founder|accept", pkg.confirm_id).as_bytes(),
                "acme",
            ),
        );
        let body = match out {
            HandlerOutcome::Ok(b) => b,
            HandlerOutcome::Err(e) => panic!("accept: {} {}", e.kind, e.cause),
        };
        let v: serde_json::Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(v["outcome"], "approved");
        assert_eq!(v["created"].as_array().unwrap().len(), 2);
        assert_eq!(s.list_subbriefs(&parent).unwrap().len(), 2);
    }

    // §1.9 hint gate on the plan-confirm path: an unhonourable assignee hint on
    // a linked child refuses the WHOLE accept BEFORE the confirm is approved and
    // BEFORE any child is created — the confirm stays open for a retry.
    #[test]
    fn plan_confirm_handler_invalid_hint_refused_no_partial() {
        let s = TaskStore::in_memory().unwrap();
        let astore = agent::AgentStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let pkg = open_pkg_handler(
            &s,
            &parent,
            "acme",
            // Second child names a role with no active Operative → unhonourable.
            serde_json::json!([{ "title": "A" }, { "title": "B", "assignee_role": "ghost" }]),
        );
        let out = handle_brief_plan_confirm_respond(
            &s,
            Some(&astore),
            &ctx_op_tenant(
                format!("{parent}|{}|founder|accept", pkg.confirm_id).as_bytes(),
                "acme",
            ),
        );
        assert!(
            matches!(out, HandlerOutcome::Err(_)),
            "bad hint refuses accept"
        );
        // No child created; both linked cards stay open (a retry is possible).
        assert!(
            s.list_subbriefs(&parent).unwrap().is_empty(),
            "no partial creation"
        );
        let cards = s.list_interactions(&parent).unwrap();
        let confirm = cards
            .iter()
            .find(|c| c.interaction_id == pkg.confirm_id)
            .unwrap();
        let suggestion = cards
            .iter()
            .find(|c| c.interaction_id == pkg.suggestion_id)
            .unwrap();
        assert_eq!(confirm.status, "open", "confirm not approved on a bad hint");
        assert_eq!(suggestion.status, "open", "suggestion not materialized");
    }

    // Tenant isolation: a cross-Guild caller can neither open a plan package nor
    // accept a plan confirm for another Guild — the owning Brief reads as
    // not-found (no existence leak).
    #[test]
    fn plan_package_denied_across_tenant() {
        let s = TaskStore::in_memory().unwrap();
        let astore = agent::AgentStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        // Cross-tenant open is refused.
        let open_arg = serde_json::json!({
            "task_id": parent, "author": "op", "plan_body": "b",
            "summary": "s", "children": [{ "title": "A" }],
        });
        let open_bytes = serde_json::to_vec(&open_arg).unwrap();
        assert!(matches!(
            handle_brief_plan_package_open(&s, &ctx_op_tenant(&open_bytes, "globex")),
            HandlerOutcome::Err(_)
        ));
        // Same-tenant open succeeds.
        let pkg = open_pkg_handler(&s, &parent, "acme", serde_json::json!([{ "title": "A" }]));
        // Cross-tenant accept is refused (not-found on the owning Brief), and
        // nothing materializes.
        let out = handle_brief_plan_confirm_respond(
            &s,
            Some(&astore),
            &ctx_op_tenant(
                format!("{parent}|{}|hacker|accept", pkg.confirm_id).as_bytes(),
                "globex",
            ),
        );
        assert!(matches!(out, HandlerOutcome::Err(_)));
        assert!(s.list_subbriefs(&parent).unwrap().is_empty());
        // Still open for the owning Guild.
        let confirm = s
            .list_interactions(&parent)
            .unwrap()
            .into_iter()
            .find(|c| c.interaction_id == pkg.confirm_id)
            .unwrap();
        assert_eq!(confirm.status, "open");
    }

    // ── Exactly-once plan decomposition (§1.7): the durable decomposition
    //    claim makes an accepted plan resumable and non-duplicating. ──

    // Helper: read the decomposition claim row (fingerprint, created_ids,
    // status) for a card, or None when no claim exists yet.
    fn decomp_claim(s: &TaskStore, task: &str, iid: &str) -> Option<(String, String, String)> {
        let conn = s.conn.lock().unwrap();
        conn.query_row(
            "SELECT fingerprint, created_ids, status FROM brief_decomposition_claims
             WHERE task_id = ?1 AND interaction_id = ?2",
            rusqlite::params![task, iid],
            |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?)),
        )
        .ok()
    }

    // Helper: read a decomposition claim's (owner, updated_at) — used by the
    // owner-takeover tests.
    fn decomp_owner(s: &TaskStore, task: &str, iid: &str) -> Option<(String, i64)> {
        let conn = s.conn.lock().unwrap();
        conn.query_row(
            "SELECT owner, updated_at FROM brief_decomposition_claims
             WHERE task_id = ?1 AND interaction_id = ?2",
            rusqlite::params![task, iid],
            |r| Ok((r.get(0)?, r.get(1)?)),
        )
        .ok()
    }

    // Helper: backdate a claim's `updated_at` by `secs` so the stale-takeover
    // threshold fires without sleeping (mirrors the direct-DB-seed pattern the
    // other decomposition tests use).
    fn backdate_claim(s: &TaskStore, task: &str, iid: &str, secs: i64) {
        let conn = s.conn.lock().unwrap();
        conn.execute(
            "UPDATE brief_decomposition_claims SET updated_at = updated_at - ?1
             WHERE task_id = ?2 AND interaction_id = ?3",
            rusqlite::params![secs, task, iid],
        )
        .unwrap();
    }

    // Helper: count `brief.suggestion_materialized` Chronicle events on a Brief.
    fn materialized_count(s: &TaskStore, parent: &str) -> usize {
        s.query_events(
            parent,
            0,
            200,
            Some("brief.suggestion_materialized"),
            EventOrder::Asc,
        )
        .unwrap()
        .len()
    }

    fn open_plan(s: &TaskStore, parent: &str, titles: &[&str]) -> String {
        let children: Vec<brief::ChildSpec> = titles
            .iter()
            .map(|t| brief::ChildSpec {
                title: (*t).into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            })
            .collect();
        s.open_suggestion(parent, "operative-1", "Break it down", &children)
            .unwrap()
    }

    // A fresh full accept creates all children, links them, records an
    // in-order cursor on a `complete` claim, and Chronicles once.
    #[test]
    fn decomposition_full_accept_records_complete_claim() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B", "C"]);
        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        assert_eq!(created.len(), 3);
        assert_eq!(s.list_subbriefs(&parent).unwrap().len(), 3);
        let (_, ids, status) = decomp_claim(&s, &parent, &id).expect("claim exists");
        assert_eq!(status, "complete");
        assert_eq!(ids, created.join(","), "cursor holds the ordered ids");
        assert_eq!(materialized_count(&s, &parent), 1);
    }

    // A duplicate accept of an already-complete plan is a no-op: it returns
    // the same ordered ids and creates no new children or events.
    #[test]
    fn decomposition_duplicate_accept_is_noop() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B"]);
        let first = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        let second = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        assert_eq!(first, second, "duplicate accept returns the same ids");
        assert_eq!(
            s.list_subbriefs(&parent).unwrap().len(),
            2,
            "no duplicate children"
        );
        assert_eq!(
            materialized_count(&s, &parent),
            1,
            "no duplicate materialized event"
        );
    }

    // Helper: count brief/manual Task rows in a tenant. Every materialized
    // child (and a test parent) is created via `create_brief`, which stamps
    // `flow_template = 'brief/manual'`, so this is the total Brief row count —
    // a CAS-loser orphan would show up here as an EXTRA, unlinked row.
    fn count_brief_manual_tasks(s: &TaskStore, tenant: &str) -> i64 {
        let conn = s.conn.lock().unwrap();
        conn.query_row(
            "SELECT COUNT(*) FROM tasks WHERE flow_template = 'brief/manual' AND tenant_id = ?1",
            rusqlite::params![tenant],
            |r| r.get(0),
        )
        .unwrap()
    }

    // §1.7 (orphan-free concurrent accept): two threads accept the SAME
    // `suggest_tasks` card at once. The per-decomposition materialization lock
    // serializes them, so EXACTLY the planned children are created and linked —
    // the CAS slot-loser can never leave an extra, unlinked orphan child Brief.
    // Both racers converge on the same ordered ids, and the plan materializes
    // exactly once. (This is the real-thread proof; the deterministic resume
    // tests above pin the crash path.)
    #[test]
    fn decomposition_concurrent_accepts_never_orphan_a_child() {
        let s = Arc::new(TaskStore::in_memory().unwrap());
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        // A wider plan widens the race window the lock has to close.
        let id = open_plan(&s, &parent, &["A", "B", "C", "D", "E"]);

        // One brief/manual row exists right now: the parent itself.
        assert_eq!(count_brief_manual_tasks(&s, "acme"), 1);

        let barrier = Arc::new(std::sync::Barrier::new(2));
        let mut handles = Vec::new();
        for _ in 0..2 {
            let s = s.clone();
            let parent = parent.clone();
            let id = id.clone();
            let barrier = barrier.clone();
            handles.push(std::thread::spawn(move || {
                barrier.wait();
                s.respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
                    .unwrap()
            }));
        }
        let results: Vec<Vec<String>> = handles.into_iter().map(|h| h.join().unwrap()).collect();

        // Both accepts see the SAME materialized plan (same ordered child ids).
        assert_eq!(
            results[0], results[1],
            "concurrent accepts converge on one plan"
        );
        assert_eq!(results[0].len(), 5, "the full plan, exactly once");

        // Exactly the five planned children are linked as Sub-briefs — no dup.
        let subs = s.list_subbriefs(&parent).unwrap();
        assert_eq!(
            subs.len(),
            5,
            "exactly the planned children, none duplicated"
        );
        for c in &results[0] {
            assert!(subs.contains(c), "{c} must be linked under the parent");
        }

        // The orphan proof: total Brief rows = parent (1) + the five children.
        // A CAS slot-loser orphan from the race would push this to 7+.
        assert_eq!(
            count_brief_manual_tasks(&s, "acme"),
            1 + 5,
            "no unlinked orphan child Brief survived the concurrent accept"
        );

        // The claim is complete with the ordered ids, materialized exactly once.
        let (_, ids, status) = decomp_claim(&s, &parent, &id).unwrap();
        assert_eq!(status, "complete");
        assert_eq!(ids, results[0].join(","));
        assert_eq!(
            materialized_count(&s, &parent),
            1,
            "the plan materialized exactly once across both racers"
        );
    }

    // A crash mid-materialization (the test fail-after hook) leaves a durable
    // partial cursor; a follow-up accept RESUMES — creating only the missing
    // children, reusing the already-created ones, and finalizing once.
    #[test]
    fn decomposition_resumes_from_partial_cursor() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B", "C"]);
        // Crash after creating exactly one child.
        let err = s
            .respond_suggestion_failing_after("acme", "subj", &parent, &id, "founder", &[], 1)
            .unwrap_err();
        assert!(matches!(err, CoordinatorError::Invalid(_)));
        // One child id is durably recorded; the claim is still in_progress.
        let (_, ids_after_crash, status) = decomp_claim(&s, &parent, &id).expect("claim exists");
        let partial = split_csv_ids(&ids_after_crash);
        assert_eq!(partial.len(), 1, "exactly one child recorded before crash");
        assert_eq!(status, "in_progress");
        // The crashed call linked nothing yet (link happens post-loop).
        assert!(s.list_subbriefs(&parent).unwrap().is_empty());
        let child_a = partial[0].clone();

        // Resume: only the two missing children are created; the first is reused.
        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        assert_eq!(created.len(), 3, "the full ordered list, exactly once");
        assert_eq!(
            created[0], child_a,
            "the pre-crash child is reused, not re-created"
        );
        let subs = s.list_subbriefs(&parent).unwrap();
        assert_eq!(subs.len(), 3, "all three linked, none duplicated");
        for c in &created {
            assert!(subs.contains(c));
        }
        // Exactly one resume event + one final materialized event.
        assert_eq!(materialized_count(&s, &parent), 1);
        assert_eq!(
            s.query_events(
                &parent,
                0,
                200,
                Some("brief.suggestion_resumed"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1
        );
        let (_, ids, fstatus) = decomp_claim(&s, &parent, &id).unwrap();
        assert_eq!(fstatus, "complete");
        assert_eq!(ids, created.join(","));
    }

    // `after` dependencies are wired correctly even when materialization is
    // resumed across a crash (edges are wired post-loop on the finishing call).
    #[test]
    fn decomposition_after_edges_survive_resume() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        // A, B(after A), C(after B).
        let children = vec![
            brief::ChildSpec {
                title: "A".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            },
            brief::ChildSpec {
                title: "B".into(),
                priority: None,
                after: Some(0),
                assignee_agent_id: None,
                assignee_role: None,
            },
            brief::ChildSpec {
                title: "C".into(),
                priority: None,
                after: Some(1),
                assignee_agent_id: None,
                assignee_role: None,
            },
        ];
        let id = s
            .open_suggestion(&parent, "op", "ordered plan", &children)
            .unwrap();
        // Crash after the first child (no edges wired yet).
        let _ = s
            .respond_suggestion_failing_after("acme", "subj", &parent, &id, "founder", &[], 1)
            .unwrap_err();
        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        assert_eq!(created.len(), 3);
        // B blocked_on A; C blocked_on B.
        assert_eq!(s.list_snags(&created[1]).unwrap(), vec![created[0].clone()]);
        assert_eq!(s.list_snags(&created[2]).unwrap(), vec![created[1].clone()]);
    }

    // A second accept of the same card with a CHANGED proposal (different
    // fingerprint) is refused — the accepted plan cannot fork — and creates
    // no further children.
    #[test]
    fn decomposition_changed_fingerprint_refuses_fork() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B", "C"]);
        // Start the decomposition (crash after one), so a claim with the
        // original fingerprint exists.
        let _ = s
            .respond_suggestion_failing_after("acme", "subj", &parent, &id, "founder", &[], 1)
            .unwrap_err();
        let (fp_before, ids_before, _) = decomp_claim(&s, &parent, &id).unwrap();
        // Mutate the card's stored proposal to a DIFFERENT plan (same card id).
        let forked = serde_json::to_string(&brief::Proposal {
            summary: "Break it down".into(),
            children: vec![brief::ChildSpec {
                title: "Totally different".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            }],
        })
        .unwrap();
        {
            let conn = s.conn.lock().unwrap();
            conn.execute(
                "UPDATE brief_interactions SET proposal = ?1 WHERE interaction_id = ?2",
                rusqlite::params![forked, id],
            )
            .unwrap();
        }
        // The fork is refused with a typed Invalid error.
        let err = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap_err();
        assert!(
            matches!(err, CoordinatorError::Invalid(_)),
            "fork must refuse"
        );
        // The claim is untouched: same fingerprint + same cursor, no new children.
        let (fp_after, ids_after, status) = decomp_claim(&s, &parent, &id).unwrap();
        assert_eq!(fp_after, fp_before, "fingerprint unchanged");
        assert_eq!(ids_after, ids_before, "cursor unchanged — no fork created");
        assert_eq!(status, "in_progress");
        assert_eq!(
            split_csv_ids(&ids_after).len(),
            1,
            "only the original partial child"
        );
    }

    // Owner takeover (§1.7): the SAME responder always resumes its own
    // in_progress claim, fresh or stale (the owner is the original accepter
    // retrying after a crash).
    #[test]
    fn decomposition_same_owner_resumes_in_progress_claim() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B", "C"]);
        // Crash after one child → an in_progress claim owned by "founder".
        let _ = s
            .respond_suggestion_failing_after("acme", "subj", &parent, &id, "founder", &[], 1)
            .unwrap_err();
        let (_, ids, status) = decomp_claim(&s, &parent, &id).unwrap();
        assert_eq!(status, "in_progress");
        assert_eq!(split_csv_ids(&ids).len(), 1);
        // The same owner resumes even while the claim is still FRESH.
        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        assert_eq!(created.len(), 3, "same owner resumes to completion");
        let (_, _, fstatus) = decomp_claim(&s, &parent, &id).unwrap();
        assert_eq!(fstatus, "complete");
        // No takeover event was emitted (same owner is never a takeover).
        assert_eq!(
            s.query_events(
                &parent,
                0,
                200,
                Some("brief.suggestion_taken_over"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            0
        );
    }

    // Owner guard (§1.7): a DIFFERENT responder cannot take over a FRESH
    // in_progress claim — the original owner may still be mid-plan / about to
    // retry. The refusal is typed and creates no further children.
    #[test]
    fn decomposition_different_owner_refused_on_fresh_claim() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B", "C"]);
        // "founder" crashes after one child → fresh in_progress claim.
        let _ = s
            .respond_suggestion_failing_after("acme", "subj", &parent, &id, "founder", &[], 1)
            .unwrap_err();
        // A different responder is refused while the claim is fresh.
        let err = s
            .respond_suggestion("acme", "subj", &parent, &id, "intruder", true, &[])
            .unwrap_err();
        assert!(
            matches!(err, CoordinatorError::Invalid(_)),
            "a different owner cannot steal a fresh in_progress claim"
        );
        // The claim is untouched: still owned by founder, still one child, no
        // new children materialized.
        let (owner, _) = decomp_owner(&s, &parent, &id).unwrap();
        assert_eq!(owner, "founder", "ownership unchanged by the refusal");
        let (_, ids, status) = decomp_claim(&s, &parent, &id).unwrap();
        assert_eq!(status, "in_progress");
        assert_eq!(split_csv_ids(&ids).len(), 1, "no extra children created");
    }

    // Stale takeover (§1.7): once an in_progress claim has been untouched past
    // DECOMPOSITION_OWNER_STALE_SECS (the owning process crashed and never
    // resumed), a DIFFERENT responder may take it over — reassigning ownership,
    // chronicling the handoff, and resuming from the durable cursor.
    #[test]
    fn decomposition_different_owner_takes_over_stale_claim() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B", "C"]);
        // "founder" crashes after one child.
        let _ = s
            .respond_suggestion_failing_after("acme", "subj", &parent, &id, "founder", &[], 1)
            .unwrap_err();
        let partial = split_csv_ids(&decomp_claim(&s, &parent, &id).unwrap().1);
        assert_eq!(partial.len(), 1);
        // Age the claim past the stale threshold (no sleeping).
        backdate_claim(&s, &parent, &id, DECOMPOSITION_OWNER_STALE_SECS + 1);
        // A different responder now takes over and finishes the plan.
        let created = s
            .respond_suggestion("acme", "subj", &parent, &id, "rescuer", true, &[])
            .unwrap();
        assert_eq!(created.len(), 3, "takeover resumes to completion");
        assert_eq!(created[0], partial[0], "the pre-crash child is reused");
        // Ownership transferred + the handoff is chronicled exactly once.
        let (owner, _) = decomp_owner(&s, &parent, &id).unwrap();
        assert_eq!(owner, "rescuer", "ownership transferred to the taker");
        assert_eq!(
            s.query_events(
                &parent,
                0,
                200,
                Some("brief.suggestion_taken_over"),
                EventOrder::Asc
            )
            .unwrap()
            .len(),
            1,
            "exactly one takeover event"
        );
        // No duplicate children; the plan materialized exactly once.
        assert_eq!(s.list_subbriefs(&parent).unwrap().len(), 3);
        assert_eq!(materialized_count(&s, &parent), 1);
    }

    // Fingerprint mismatch still refuses even when the claim is STALE — the
    // fork check runs before the owner/staleness logic, so a stale claim with a
    // changed proposal cannot be taken over into a fork.
    #[test]
    fn decomposition_stale_takeover_still_refuses_fork() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B", "C"]);
        let _ = s
            .respond_suggestion_failing_after("acme", "subj", &parent, &id, "founder", &[], 1)
            .unwrap_err();
        let (fp_before, ids_before, _) = decomp_claim(&s, &parent, &id).unwrap();
        // Age the claim past the stale threshold so takeover WOULD be allowed.
        backdate_claim(&s, &parent, &id, DECOMPOSITION_OWNER_STALE_SECS + 1);
        // Fork the stored proposal under the same card id.
        let forked = serde_json::to_string(&brief::Proposal {
            summary: "Break it down".into(),
            children: vec![brief::ChildSpec {
                title: "Totally different".into(),
                priority: None,
                after: None,
                assignee_agent_id: None,
                assignee_role: None,
            }],
        })
        .unwrap();
        {
            let conn = s.conn.lock().unwrap();
            conn.execute(
                "UPDATE brief_interactions SET proposal = ?1 WHERE interaction_id = ?2",
                rusqlite::params![forked, id],
            )
            .unwrap();
        }
        // A different responder taking over a STALE claim still cannot fork.
        let err = s
            .respond_suggestion("acme", "subj", &parent, &id, "rescuer", true, &[])
            .unwrap_err();
        assert!(
            matches!(err, CoordinatorError::Invalid(_)),
            "fork must refuse"
        );
        // Claim untouched: same fingerprint, same cursor, still owned by founder
        // (the fork check refused BEFORE any takeover reassignment).
        let (fp_after, ids_after, status) = decomp_claim(&s, &parent, &id).unwrap();
        assert_eq!(fp_after, fp_before, "fingerprint unchanged");
        assert_eq!(ids_after, ids_before, "cursor unchanged");
        assert_eq!(status, "in_progress");
        let (owner, _) = decomp_owner(&s, &parent, &id).unwrap();
        assert_eq!(owner, "founder", "no takeover happened on a refused fork");
    }

    // Terminal takeover is trivial: ANY responder accepting an already-complete
    // claim no-ops and gets the recorded ids back (no owner guard, no new work).
    #[test]
    fn decomposition_complete_claim_noops_for_any_owner() {
        let s = TaskStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Epic", "subj", None, None, None, None)
            .unwrap();
        let id = open_plan(&s, &parent, &["A", "B"]);
        let first = s
            .respond_suggestion("acme", "subj", &parent, &id, "founder", true, &[])
            .unwrap();
        // A DIFFERENT responder accepting the completed plan gets the same ids,
        // creates nothing, and the claim stays owned by the original accepter.
        let second = s
            .respond_suggestion("acme", "subj", &parent, &id, "someone-else", true, &[])
            .unwrap();
        assert_eq!(first, second, "completed claim no-ops for any responder");
        assert_eq!(
            s.list_subbriefs(&parent).unwrap().len(),
            2,
            "no new children"
        );
        assert_eq!(materialized_count(&s, &parent), 1);
        let (owner, _) = decomp_owner(&s, &parent, &id).unwrap();
        assert_eq!(owner, "founder", "a no-op never reassigns ownership");
    }

    // Governance: an invalid assignee hint refuses the WHOLE accept in the
    // wire handler BEFORE respond_suggestion runs — so no decomposition claim
    // and no child is ever created (no partial materialization).
    #[test]
    fn decomposition_invalid_hint_creates_no_claim() {
        let s = TaskStore::in_memory().unwrap();
        let astore = agent::AgentStore::in_memory().unwrap();
        let parent = s
            .create_brief("acme", "Parent", "subj", None, None, None, None)
            .unwrap();
        let open_arg = serde_json::json!({
            "task_id": parent,
            "author": "op",
            "summary": "Plan",
            "children": [
                { "title": "A" },
                { "title": "B", "assignee_role": "ghost" },
            ],
        });
        let open_bytes = serde_json::to_vec(&open_arg).unwrap();
        let id = match handle_brief_suggest_open(&s, &ctx_op_tenant(&open_bytes, "acme")) {
            HandlerOutcome::Ok(b) => String::from_utf8(b).unwrap(),
            HandlerOutcome::Err(e) => panic!("open: {} {}", e.kind, e.cause),
        };
        let out = handle_brief_suggest_respond(
            &s,
            Some(&astore),
            &ctx_op_tenant(format!("{parent}|{id}|founder|accept").as_bytes(), "acme"),
        );
        assert!(matches!(out, HandlerOutcome::Err(_)), "bad hint refuses");
        assert!(s.list_subbriefs(&parent).unwrap().is_empty(), "no children");
        assert!(
            decomp_claim(&s, &parent, &id).is_none(),
            "no decomposition claim created on a pre-creation refusal"
        );
    }

    // Cross-tenant: an accept from the wrong Guild is refused at the handler
    // boundary and creates neither a decomposition claim nor any child.
    #[test]
    fn decomposition_cross_tenant_accept_creates_nothing() {
        let s = TaskStore::in_memory().unwrap();
        let a = s
            .create_brief("acme", "Acme", "subj", None, None, None, None)
            .unwrap();
        let open_arg = serde_json::json!({
            "task_id": a, "author": "op", "summary": "Plan",
            "children": [{ "title": "A" }, { "title": "B" }],
        });
        let open_bytes = serde_json::to_vec(&open_arg).unwrap();
        let id = match handle_brief_suggest_open(&s, &ctx_tenant(&open_bytes, "acme")) {
            HandlerOutcome::Ok(b) => String::from_utf8(b).unwrap(),
            HandlerOutcome::Err(_) => panic!("open errored"),
        };
        // A globex caller's accept is refused (not-found, no existence leak).
        assert!(matches!(
            handle_brief_suggest_respond(
                &s,
                None,
                &ctx_tenant(format!("{a}|{id}|hacker|accept").as_bytes(), "globex"),
            ),
            HandlerOutcome::Err(_)
        ));
        assert!(
            s.list_subbriefs(&a).unwrap().is_empty(),
            "no children leaked"
        );
        assert!(
            decomp_claim(&s, &a, &id).is_none(),
            "no claim created by a cross-tenant accept"
        );
    }

